/**
 * Vehicle API
 *
 * Dataverse operations for vehicle records: listing, detail, and search.
 *
 * RESPONSIBILITIES
 *  - Paginated, filtered, sorted vehicle listing
 *  - Single vehicle lookup by ID
 *  - Text search across make/model/spec
 *  - Full dataset fetch with pagination for client-side filtering
 *
 * RELATED MODULES
 *  - Pricing/valuation  → {@link ./pricingApi}
 *  - Analytics           → {@link ./analyticsApi}
 *  - Hierarchy/lookups   → {@link ./hierarchyApi}
 *
 * RULES
 *  - Never load all 33k+ records in a single request without pagination.
 *  - Use $select aggressively to minimise payload.
 *  - Fail gracefully — return sensible defaults, never throw.
 */

import type { Vehicle, VehicleFilters, VehicleSortOption } from '@types';

import * as dv from '@lib/dataverse/dataverseClient';
import {
  rowToVehicle,
  buildVehicleFilter,
  buildVehicleOrderBy,
  type DataverseVehicleRow,
} from '@lib/dataverse/mappers';
import {
  VEHICLE_SELECT,
  entityUrl,
  collectionUrl,
  escape,
} from './api-utils';
import { logApiError } from './api-error';

/**
 * Full vehicle select matching the Dataverse vpi_vehicledatas entity fields.
 * Includes fields needed for cascading filters and pricing display.
 */
export const FULL_VEHICLE_SELECT = [
  'vpi_vehicledataid',
  'vpi_year',
  'vpi_make',
  'vpi_makecode',
  'vpi_model',
  'vpi_modelcode',
  'vpi_spec',
  'vpi_enginesize',
  'vpi_horsepower',
  'vpi_cylinders',
  'vpi_doors',
  'vpi_seats',
  'vpi_transmissiontronic',
  'vpi_bodytype',
  'vpi_drivetype',
  'vpi_vehicletype',
  'vpi_category',
  'vpi_powertraintype',
  'vpi_description',
  'vpi_minprice',
  'vpi_avgprice',
  'vpi_maxprice',
  'vpi_pricespreadpct',
  'vpi_yearcode',
  'vpi_id',
  'vpi_name',
  'statecode',
].join(',');

/** Header to include formatted display values for option-set fields. */
const PREFER_INCLUDE_ANNOTATIONS: Record<string, string> = {
  Prefer: 'odata.include-annotations=*',
};

// ─── Vehicle CRUD ─────────────────────────────────────────────────

/**
 * Get a paginated, filtered, sorted list of vehicles.
 * NEVER loads all records — uses $top/$skip pagination.
 */
export async function getVehicles(
  filters?: VehicleFilters,
  sort?: VehicleSortOption,
  page = 1,
  pageSize = 20,
): Promise<{ vehicles: Vehicle[]; total: number }> {
  const filterClause = buildVehicleFilter(filters);
  const orderBy = sort
    ? buildVehicleOrderBy(sort.field, sort.direction)
    : 'vpi_year desc';

  const top = pageSize;
  const skip = (page - 1) * pageSize;

  const parts: string[] = [
    `?$select=${VEHICLE_SELECT}`,
    `&$top=${top}`,
    `&$skip=${skip}`,
    `&$orderby=${encodeURIComponent(orderBy)}`,
    '&$count=true',
  ];

  if (filterClause) parts.push(`&$filter=${encodeURIComponent(filterClause)}`);

  const url = collectionUrl(parts.join(''));
  const response = await dv.get<{
    value: DataverseVehicleRow[];
    '@odata.count'?: number;
  }>(url, PREFER_INCLUDE_ANNOTATIONS);

  if (!response.ok) {
    logApiError('getVehicles', response.status);
    return { vehicles: [], total: 0 };
  }

  const raw = response.data;
  const vehicles = (raw.value ?? []).map(rowToVehicle);
  const total = raw['@odata.count'] ?? vehicles.length;

  return { vehicles, total };
}

/**
 * Get a single vehicle by its GUID.
 */
export async function getVehicleById(id: string): Promise<Vehicle | null> {
  const url = `${entityUrl(id)}?$select=${VEHICLE_SELECT}`;
  const response = await dv.get<DataverseVehicleRow>(url);

  if (!response.ok) {
    logApiError('getVehicleById', response.status, `id=${id}`);
    return null;
  }

  return rowToVehicle(response.data);
}

/**
 * Search vehicles by make/model/spec text match.
 * Uses OData `substringof` (case-insensitive).
 */
export async function searchVehicles(
  query: string,
  limit = 20,
): Promise<Vehicle[]> {
  if (!query || query.length < 2) return [];

  const q = escape(query);
  const filter = `substringof('${q}', vpi_make) or substringof('${q}', vpi_model) or substringof('${q}', vpi_spec)`;
  const url = collectionUrl(
    `?$select=${VEHICLE_SELECT}&$filter=${encodeURIComponent(filter)}&$top=${limit}&$orderby=vpi_make`,
  );

  const response = await dv.get<{ value: DataverseVehicleRow[] }>(url);
  if (!response.ok) return [];

  return (response.data.value ?? []).map(rowToVehicle);
}

/**
 * Fetch ALL vehicle records from Dataverse following @odata.nextLink.
 *
 * Uses $select + $top on the initial request, then follows @odata.nextLink
 * for each subsequent page. The nextLink's absolute URL is converted to a
 * Power Pages /_api/ relative path by extracting its query string and
 * rebuilding through collectionUrl.
 *
 * @param pageSize  Records per page (Dataverse max is 5000)
 * @param maxPages  Safety limit (prevents runaway loops)
 */
export async function getAllVehicles(
  pageSize = 5000,
  maxPages = 20,
): Promise<{ vehicles: Vehicle[]; rows: DataverseVehicleRow[] }> {
  const allRows: DataverseVehicleRow[] = [];
  let nextLink: string | null = collectionUrl(`?$select=${FULL_VEHICLE_SELECT}&$top=${pageSize}`);
  let pages = 0;

  while (nextLink && pages < maxPages) {
    type PageData = {
      value: DataverseVehicleRow[];
      '@odata.nextLink'?: string;
    };
    const pageRes: dv.DataverseResponse<PageData> = await dv.get<PageData>(nextLink, PREFER_INCLUDE_ANNOTATIONS);

    if (!pageRes.ok) {
      logApiError('getAllVehicles', pageRes.status, `page=${pages + 1}`);
      break;
    }

    const pageRows = pageRes.data.value ?? [];
    allRows.push(...pageRows);

    // If we got fewer rows than requested, we've hit the last page
    if (pageRows.length < pageSize) break;

    // Follow @odata.nextLink: Dataverse returns an absolute URL like
    //   https://org...crm6.dynamics.com/api/data/v9.2/vpi_vehicledatas?$skiptoken=X
    // Map to Power Pages proxy format: /_api/vpi_vehicledatas?$skiptoken=X
    const rawNextLink = pageRes.data['@odata.nextLink'];
    if (rawNextLink) {
      try {
        const parsedUrl = new URL(rawNextLink);
        nextLink = `/_api/vpi_vehicledatas${parsedUrl.search}`;
      } catch {
        logApiError('getAllVehicles', 0, `Failed to parse nextLink: ${rawNextLink}`);
        break;
      }
    } else {
      nextLink = null;
    }

    pages++;
  }

  const vehicles = allRows.map(rowToVehicle);
  return { vehicles, rows: allRows };
}
