import { useState, useCallback } from 'react';
import { useInquiries, useUpdateInquiryStatus, useExportInquiries } from '@hooks';
import {
  Button,
  Dialog,
  SkeletonTable,
} from '@components/ui';
import { motion } from 'framer-motion';
import {
  Eye,
  X,
  ClipboardList,
  Search,
  ChevronLeft,
  ChevronRight,
  RotateCcw,
  Car,
  Calendar,
  CheckCircle2,
  Clock,
  MessageSquare,
  Mail,
  Phone,
  MapPin,
  TrendingUp,
  User,
  Check,
  ChevronDown,
  Download,
} from 'lucide-react';
import type { Inquiry, InquiryStatus } from '@types';
import { formatCurrency, cn } from '@utils';

// ─── Status helpers ──────────────────────────────────────────────

const STATUS_CONFIG: Record<InquiryStatus, { label: string; icon: React.ReactNode; className: string; dot: string }> = {
  pending: {
    label: 'Pending',
    icon: <Clock className="h-3 w-3" />,
    className: 'text-amber-600 dark:text-amber-400 bg-amber-500/10 border-amber-500/20',
    dot: 'bg-amber-500',
  },
  reviewed: {
    label: 'Reviewed',
    icon: <Eye className="h-3 w-3" />,
    className: 'text-blue-600 dark:text-blue-400 bg-blue-500/10 border-blue-500/20',
    dot: 'bg-blue-500',
  },
  contacted: {
    label: 'Contacted',
    icon: <MessageSquare className="h-3 w-3" />,
    className: 'text-violet-600 dark:text-violet-400 bg-violet-500/10 border-violet-500/20',
    dot: 'bg-violet-500',
  },
  closed: {
    label: 'Closed',
    icon: <CheckCircle2 className="h-3 w-3" />,
    className: 'text-muted-foreground bg-muted/50 border-border/50',
    dot: 'bg-muted-foreground',
  },
};

const STATUS_OPTIONS: { value: InquiryStatus; label: string }[] = [
  { value: 'pending', label: 'Pending' },
  { value: 'reviewed', label: 'Reviewed' },
  { value: 'contacted', label: 'Contacted' },
  { value: 'closed', label: 'Closed' },
];

function StatusBadge({ status }: { status: InquiryStatus }) {
  const cfg = STATUS_CONFIG[status];
  return (
    <span className={cn('inline-flex items-center gap-1.5 rounded-full border px-2.5 py-0.5 text-[11px] font-medium', cfg.className)}>
      <span className={cn('h-1.5 w-1.5 rounded-full', cfg.dot)} />
      {cfg.label}
    </span>
  );
}

// ─── Format helpers ──────────────────────────────────────────────

function formatDate(date: Date | string): string {
  const d = typeof date === 'string' ? new Date(date) : date;
  return d.toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'short',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
}

function formatShortDate(date: Date | string): string {
  const d = typeof date === 'string' ? new Date(date) : date;
  const now = new Date();
  const diff = now.getTime() - d.getTime();
  const days = Math.floor(diff / (1000 * 60 * 60 * 24));

  if (days === 0) {
    const hours = Math.floor(diff / (1000 * 60 * 60));
    if (hours === 0) {
      const mins = Math.floor(diff / (1000 * 60));
      return `${mins}m ago`;
    }
    return `${hours}h ago`;
  }
  if (days === 1) return 'Yesterday';
  if (days < 7) return `${days}d ago`;
  return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
}

// ─── Status Select ───────────────────────────────────────────────

function StatusSelect({ inquiry }: { inquiry: Inquiry }) {
  const updateStatus = useUpdateInquiryStatus();
  const [open, setOpen] = useState(false);

  const handleSelect = useCallback(
    (newStatus: InquiryStatus) => {
      setOpen(false);
      updateStatus.mutate({ id: inquiry.id, status: newStatus });
    },
    [inquiry.id, updateStatus],
  );

  const currentCfg = STATUS_CONFIG[inquiry.status];

  return (
    <div className="relative">
      <button
        onClick={() => setOpen(!open)}
        disabled={updateStatus.isPending}
        className={cn(
          'inline-flex items-center gap-2 rounded-lg border px-3 py-1.5 text-xs font-medium transition-all',
          'hover:bg-accent focus:outline-none focus:ring-2 focus:ring-ring',
          'disabled:opacity-50',
          currentCfg.className,
        )}
      >
        {currentCfg.icon}
        {currentCfg.label}
        <ChevronDown className={cn('h-3 w-3 transition-transform', open && 'rotate-180')} />
      </button>
      {open && (
        <>
          <div className="fixed inset-0 z-40" onClick={() => setOpen(false)} />
          <div className="absolute right-0 top-full z-50 mt-1 w-36 overflow-hidden rounded-xl border bg-popover shadow-lg">
            {STATUS_OPTIONS.map((opt) => {
              const cfg = STATUS_CONFIG[opt.value];
              const isActive = inquiry.status === opt.value;
              return (
                <button
                  key={opt.value}
                  onClick={() => handleSelect(opt.value)}
                  className={cn(
                    'flex w-full items-center gap-2.5 px-3 py-2 text-xs font-medium transition-colors',
                    isActive
                      ? 'bg-accent text-foreground'
                      : 'text-muted-foreground hover:bg-accent/50 hover:text-foreground',
                  )}
                >
                  <span className={cn('h-1.5 w-1.5 rounded-full', cfg.dot)} />
                  {cfg.label}
                  {isActive && <Check className="ml-auto h-3 w-3 text-primary" />}
                </button>
              );
            })}
          </div>
        </>
      )}
    </div>
  );
}

// ─── Inquiry Detail Modal ────────────────────────────────────────

function InquiryDetailModal({
  inquiry,
  isOpen,
  onClose,
}: {
  inquiry: Inquiry;
  isOpen: boolean;
  onClose: () => void;
}) {
  const vehicle = inquiry.selectedVehicle;
  const vehicleDisplay = `${vehicle.year} ${vehicle.make} ${vehicle.model} ${vehicle.spec}`.trim();

  return (
    <Dialog
      isOpen={isOpen}
      onClose={onClose}
      title=""
      description=""
      size="xl"
      hideCloseButton
    >
      <div className="flex max-h-[75vh] flex-col gap-0">
        {/* Header section with gradient */}
        <div className="shrink-0 -mx-6 -mt-6 rounded-t-2xl bg-gradient-to-br from-primary/10 via-primary/5 to-transparent px-6 pb-4 pt-5">
          <div className="flex items-start justify-between">
            <div className="flex items-start gap-3.5">
              <div className="flex h-12 w-12 shrink-0 items-center justify-center rounded-xl bg-gradient-to-br from-primary/20 to-primary/5 shadow-sm">
                <User className="h-6 w-6 text-primary" />
              </div>
              <div>
                <h2 className="text-lg font-bold text-foreground">
                  {inquiry.firstName} {inquiry.lastName}
                </h2>
                <p className="mt-0.5 flex items-center gap-1.5 text-xs text-muted-foreground">
                  <Calendar className="h-3 w-3" />
                  Submitted {formatDate(inquiry.createdAt)}
                </p>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <StatusSelect inquiry={inquiry} />
              <button
                onClick={onClose}
                className="rounded-lg p-1.5 text-muted-foreground transition-colors hover:bg-background/80 hover:text-foreground"
              >
                <X className="h-4 w-4" />
              </button>
            </div>
          </div>
        </div>

        {/* Scrollable body */}
        <div className="flex-1 overflow-y-auto px-6 py-4">
          {/* Contact Info */}
          <div className="mb-4 grid grid-cols-2 gap-4">
            <div className="rounded-xl border bg-card p-3.5">
              <p className="flex items-center gap-1.5 text-[10px] uppercase tracking-wider text-muted-foreground">
                <Mail className="h-3 w-3" />
                Email
              </p>
              <p className="mt-1 text-sm font-medium text-foreground truncate">{inquiry.email}</p>
            </div>
            <div className="rounded-xl border bg-card p-3.5">
              <p className="flex items-center gap-1.5 text-[10px] uppercase tracking-wider text-muted-foreground">
                <Phone className="h-3 w-3" />
                Phone
              </p>
              <p className="mt-1 text-sm font-medium text-foreground">{inquiry.phone}</p>
            </div>
          </div>

          {/* Location */}
          <div className="mb-4 rounded-xl border bg-card p-3.5">
            <p className="flex items-center gap-1.5 text-[10px] uppercase tracking-wider text-muted-foreground">
              <MapPin className="h-3 w-3" />
              Location
            </p>
            <p className="mt-1 text-sm font-medium text-foreground">
              {inquiry.city}, {inquiry.country}
            </p>
          </div>

          {/* Selected Vehicle */}
          <div className="mb-4 overflow-hidden rounded-xl border">
            <div className="flex items-center gap-2 border-b bg-muted/30 px-4 py-2.5">
              <Car className="h-4 w-4 text-primary" />
              <span className="text-xs font-semibold uppercase tracking-wider text-foreground">Selected Vehicle</span>
            </div>
            <div className="grid grid-cols-2 divide-x divide-y divide-border sm:grid-cols-3">
              {[
                { label: 'Year', value: vehicle.year },
                { label: 'Make', value: vehicle.make },
                { label: 'Model', value: vehicle.model },
                { label: 'Spec', value: vehicle.spec },
                { label: 'Body Type', value: vehicle.bodyType },
                { label: 'Trim', value: vehicleDisplay },
              ].map((item) => (
                <div key={item.label} className="px-4 py-2.5">
                  <p className="text-[10px] uppercase tracking-wider text-muted-foreground">{item.label}</p>
                  <p className="mt-0.5 text-xs font-medium text-foreground truncate" title={String(item.value)}>{item.value}</p>
                </div>
              ))}
            </div>
          </div>

          {/* Valuation Result */}
          {inquiry.valuationResult ? (
            <div className="overflow-hidden rounded-xl border">
              <div className="flex items-center gap-2 border-b bg-muted/30 px-4 py-2.5">
                <TrendingUp className="h-4 w-4 text-emerald-600 dark:text-emerald-400" />
                <span className="text-xs font-semibold uppercase tracking-wider text-foreground">Valuation Result</span>
              </div>
              <div className="grid grid-cols-3 divide-x divide-border">
                <div className="bg-gradient-to-br from-primary/5 to-transparent p-4">
                  <p className="text-[10px] uppercase tracking-wider text-muted-foreground">Min Price</p>
                  <p className="mt-0.5 text-lg font-bold text-primary">
                    {formatCurrency(inquiry.valuationResult.pricing.minimumPrice)}
                  </p>
                </div>
                <div className="p-4">
                  <p className="text-[10px] uppercase tracking-wider text-muted-foreground">Median Price</p>
                  <p className="mt-0.5 text-lg font-bold text-foreground">
                    {formatCurrency(inquiry.valuationResult.pricing.medianPrice)}
                  </p>
                </div>
                <div className="p-4">
                  <p className="text-[10px] uppercase tracking-wider text-muted-foreground">Max Price</p>
                  <p className="mt-0.5 text-lg font-bold text-foreground">
                    {formatCurrency(inquiry.valuationResult.pricing.maximumPrice)}
                  </p>
                </div>
              </div>
            </div>
          ) : (
            <div className="flex items-center justify-center rounded-xl border border-dashed p-8 text-center">
              <p className="text-sm text-muted-foreground">No valuation data available for this inquiry.</p>
            </div>
          )}
        </div>
      </div>
    </Dialog>
  );
}

// ─── Animations ──────────────────────────────────────────────────

const containerVariants = {
  hidden: { opacity: 0 },
  visible: { opacity: 1, transition: { staggerChildren: 0.03 } },
};
const itemVariants = {
  hidden: { opacity: 0, y: 12 },
  visible: { opacity: 1, y: 0 },
};

// ─── Main Page ───────────────────────────────────────────────────

export function AdminQueriesPage() {
  const [search, setSearch] = useState('');
  const [selectedInquiry, setSelectedInquiry] = useState<Inquiry | null>(null);
  const [page, setPage] = useState(1);
  const [statusFilter, setStatusFilter] = useState<InquiryStatus | 'all'>('all');
  const pageSize = 15;

  const { data: inquiries, isLoading } = useInquiries();
  const exportInquiries = useExportInquiries();

  // Filter by search and status
  const filtered = (inquiries ?? []).filter((inq) => {
    if (statusFilter !== 'all' && inq.status !== statusFilter) return false;
    if (!search) return true;
    const q = search.toLowerCase();
    return (
      inq.firstName.toLowerCase().includes(q) ||
      inq.lastName.toLowerCase().includes(q) ||
      inq.email.toLowerCase().includes(q) ||
      inq.phone.includes(q) ||
      `${inq.selectedVehicle.year} ${inq.selectedVehicle.make} ${inq.selectedVehicle.model} ${inq.selectedVehicle.spec}`.toLowerCase().includes(q)
    );
  });

  // Sort by newest first
  const sorted = [...filtered].sort(
    (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime(),
  );

  const totalPages = Math.max(1, Math.ceil(sorted.length / pageSize));
  const paginated = sorted.slice((page - 1) * pageSize, page * pageSize);

  // Status counts for the summary bar
  const statusCounts = {
    all: inquiries?.length ?? 0,
    pending: inquiries?.filter((i) => i.status === 'pending').length ?? 0,
    reviewed: inquiries?.filter((i) => i.status === 'reviewed').length ?? 0,
    contacted: inquiries?.filter((i) => i.status === 'contacted').length ?? 0,
    closed: inquiries?.filter((i) => i.status === 'closed').length ?? 0,
  };

  const getPageNumbers = useCallback(() => {
    const pages: (number | 'ellipsis')[] = [];
    const maxVisible = 5;
    if (totalPages <= maxVisible + 2) {
      for (let i = 1; i <= totalPages; i++) pages.push(i);
    } else {
      pages.push(1);
      let start = Math.max(2, page - 1);
      let end = Math.min(totalPages - 1, page + 1);
      if (start > 2) pages.push('ellipsis');
      for (let i = start; i <= end; i++) pages.push(i);
      if (end < totalPages - 1) pages.push('ellipsis');
      pages.push(totalPages);
    }
    return pages;
  }, [totalPages, page]);

  return (
    <motion.div
      className="space-y-5"
      variants={containerVariants}
      initial="hidden"
      animate="visible"
    >
      {/* Header */}
      <motion.div variants={itemVariants}>
        <div className="flex flex-col items-start justify-between gap-4 md:flex-row md:items-center">
          <div>
            <h1 className="text-2xl font-bold tracking-tight text-foreground">Queries</h1>
            <p className="text-sm text-muted-foreground">
              <span className="font-medium text-foreground">{inquiries?.length ?? 0}</span> total inquiries
              {statusCounts.pending > 0 && (
                <>
                  <span className="mx-1.5 text-muted-foreground/30">·</span>
                  <span className="font-medium text-amber-600 dark:text-amber-400">
                    {statusCounts.pending} pending
                  </span>
                </>
              )}
            </p>
          </div>
          <div className="flex items-center gap-2">
            <Button
              variant="outline"
              size="sm"
              onClick={exportInquiries}
              disabled={!inquiries?.length}
              title="Export all inquiries as Excel"
            >
              <Download className="mr-1.5 h-4 w-4" />
              Export
            </Button>
            <div className="relative">
              <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground/50" />
              <input
                type="text"
                placeholder="Search by name, email, vehicle..."
                value={search}
                onChange={(e) => {
                  setSearch(e.target.value);
                  setPage(1);
                }}
                className="h-9 w-48 rounded-lg border bg-background/50 pl-9 pr-3 text-sm outline-none transition-colors placeholder:text-muted-foreground/40 focus:border-primary/50 focus:bg-background md:w-72"
              />
            </div>
            {search && (
              <Button variant="ghost" size="sm" onClick={() => { setSearch(''); setPage(1); }}>
                <RotateCcw className="mr-1.5 h-3 w-3" />
                Clear
              </Button>
            )}
          </div>
        </div>
      </motion.div>

      {/* Status filter tabs */}
      <motion.div variants={itemVariants}>
        <div className="flex items-center gap-1.5 rounded-xl border bg-card p-1.5 overflow-x-auto">
          {[
            { key: 'all' as const, label: 'All', count: statusCounts.all, color: '' },
            { key: 'pending' as const, label: 'Pending', count: statusCounts.pending, color: 'bg-amber-500' },
            { key: 'reviewed' as const, label: 'Reviewed', count: statusCounts.reviewed, color: 'bg-blue-500' },
            { key: 'contacted' as const, label: 'Contacted', count: statusCounts.contacted, color: 'bg-violet-500' },
            { key: 'closed' as const, label: 'Closed', count: statusCounts.closed, color: 'bg-muted-foreground' },
          ].map((tab) => (
            <button
              key={tab.key}
              onClick={() => { setStatusFilter(tab.key); setPage(1); }}
              className={cn(
                'flex items-center gap-2 rounded-lg px-3.5 py-2 text-xs font-medium transition-all whitespace-nowrap',
                statusFilter === tab.key
                  ? 'bg-primary/10 text-primary shadow-sm'
                  : 'text-muted-foreground hover:text-foreground hover:bg-accent/50',
              )}
            >
              {tab.color && <span className={cn('h-1.5 w-1.5 rounded-full', tab.color)} />}
              {tab.label}
              <span className={cn(
                'ml-0.5 rounded-full px-1.5 py-0.5 text-[10px] font-semibold',
                statusFilter === tab.key
                  ? 'bg-primary/15 text-primary'
                  : 'bg-muted text-muted-foreground',
              )}>
                {tab.count}
              </span>
            </button>
          ))}
        </div>
      </motion.div>

      {/* Table card */}
      <motion.div variants={itemVariants}>
        <div className="rounded-2xl border bg-card overflow-hidden">
          {/* Gradient top bar */}
          <div className="h-1 bg-gradient-to-r from-primary/60 via-accent/60 to-primary/30" />

          {isLoading ? (
            <div className="p-6">
              <SkeletonTable rows={8} cols={8} />
            </div>
          ) : paginated.length > 0 ? (
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead>
                  <tr className="border-b bg-muted/20">
                    <th className="w-10 px-4 py-3.5 text-left text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">#</th>
                    <th className="px-4 py-3.5 text-left text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">Customer</th>
                    <th className="px-4 py-3.5 text-left text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">Contact</th>
                    <th className="px-4 py-3.5 text-left text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">Vehicle</th>
                    <th className="px-4 py-3.5 text-left text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">Body</th>
                    <th className="px-4 py-3.5 text-left text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">Status</th>
                    <th className="px-4 py-3.5 text-left text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">Date</th>
                    <th className="px-4 py-3.5 text-right text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y">
                  {paginated.map((inquiry, i) => {
                    const vehicleDisplay = `${inquiry.selectedVehicle.year} ${inquiry.selectedVehicle.make} ${inquiry.selectedVehicle.model}`.trim();
                    return (
                      <tr
                        key={inquiry.id}
                        className="group/row transition-colors hover:bg-muted/30 cursor-pointer"
                        onClick={() => setSelectedInquiry(inquiry)}
                      >
                        <td className="px-4 py-3 text-xs text-muted-foreground">
                          {(page - 1) * pageSize + i + 1}
                        </td>
                        <td className="px-4 py-3">
                          <div className="flex items-center gap-3">
                            <div className={cn(
                              'flex h-8 w-8 shrink-0 items-center justify-center rounded-full text-xs font-bold',
                              STATUS_CONFIG[inquiry.status].className,
                            )}>
                              {inquiry.firstName[0]}{inquiry.lastName[0]}
                            </div>
                            <div>
                              <p className="font-medium text-foreground whitespace-nowrap">
                                {inquiry.firstName} {inquiry.lastName}
                              </p>
                              <p className="text-xs text-muted-foreground">
                                {inquiry.city}
                              </p>
                            </div>
                          </div>
                        </td>
                        <td className="px-4 py-3">
                          <div className="space-y-0.5">
                            <p className="text-xs text-foreground/80 whitespace-nowrap flex items-center gap-1.5">
                              <Mail className="h-3 w-3 text-muted-foreground/50" />
                              {inquiry.email}
                            </p>
                            <p className="text-xs text-foreground/80 whitespace-nowrap flex items-center gap-1.5">
                              <Phone className="h-3 w-3 text-muted-foreground/50" />
                              {inquiry.phone}
                            </p>
                          </div>
                        </td>
                        <td className="px-4 py-3 max-w-[200px]">
                          <p className="text-sm font-medium text-foreground truncate" title={vehicleDisplay}>
                            {vehicleDisplay}
                          </p>
                          <p className="text-xs text-muted-foreground truncate">{inquiry.selectedVehicle.spec}</p>
                        </td>
                        <td className="px-4 py-3 whitespace-nowrap">
                          <span className="text-xs text-foreground/80">{inquiry.selectedVehicle.bodyType}</span>
                        </td>
                        <td className="px-4 py-3 whitespace-nowrap">
                          <StatusBadge status={inquiry.status} />
                        </td>
                        <td className="px-4 py-3 whitespace-nowrap">
                          <div className="flex flex-col">
                            <span className="text-xs text-foreground">{formatShortDate(inquiry.createdAt)}</span>
                            <span className="text-[10px] text-muted-foreground">
                              {new Date(inquiry.createdAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                            </span>
                          </div>
                        </td>
                        <td className="px-4 py-3 text-right whitespace-nowrap">
                          <div className="flex items-center justify-end gap-1 opacity-0 group-hover/row:opacity-100 transition-opacity">
                            <Button
                              variant="ghost"
                              size="icon-sm"
                              title="View details"
                              onClick={(e) => { e.stopPropagation(); setSelectedInquiry(inquiry); }}
                            >
                              <Eye className="h-4 w-4" />
                            </Button>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          ) : (
            <div className="flex flex-col items-center justify-center py-20">
              <div className="mb-4 flex h-20 w-20 items-center justify-center rounded-2xl bg-gradient-to-br from-muted to-muted/50">
                <ClipboardList className="h-10 w-10 text-muted-foreground/60" />
              </div>
              <p className="text-lg font-medium text-foreground">
                {search || statusFilter !== 'all' ? 'No matching inquiries' : 'No inquiries yet'}
              </p>
              <p className="mt-1 text-sm text-muted-foreground text-center max-w-sm">
                {search
                  ? 'Try adjusting your search or filter.'
                  : statusFilter !== 'all'
                    ? `No inquiries with "${STATUS_CONFIG[statusFilter as InquiryStatus]?.label}" status.`
                    : 'When users complete a valuation on the portal, their details will appear here.'}
              </p>
              {(search || statusFilter !== 'all') && (
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => { setSearch(''); setStatusFilter('all'); }}
                  className="mt-4"
                >
                  <RotateCcw className="mr-1.5 h-3 w-3" />
                  Clear filters
                </Button>
              )}
            </div>
          )}
        </div>
      </motion.div>

      {/* Pagination */}
      {sorted.length > pageSize && (
        <motion.div variants={itemVariants}>
          <div className="flex flex-col items-center justify-between gap-3 sm:flex-row">
            <p className="text-sm text-muted-foreground">
              Page <span className="text-foreground">{page}</span> of <span className="text-foreground">{totalPages}</span>
              <span className="mx-2 text-muted-foreground/30">·</span>
              <span>{sorted.length} total</span>
            </p>
            <div className="flex items-center gap-1.5">
              <Button variant="outline" size="sm" disabled={page <= 1} onClick={() => setPage(1)} title="First page">
                <ChevronLeft className="h-3.5 w-3.5" />
                <ChevronLeft className="-ml-2 h-3.5 w-3.5" />
              </Button>
              <Button variant="outline" size="sm" disabled={page <= 1} onClick={() => setPage(page - 1)}>
                <ChevronLeft className="h-4 w-4" />
              </Button>
              <div className="flex items-center gap-1">
                {getPageNumbers().map((pageNum, idx) =>
                  pageNum === 'ellipsis' ? (
                    <span key={`e-${idx}`} className="px-1 text-muted-foreground">…</span>
                  ) : (
                    <Button
                      key={pageNum}
                      variant={page === pageNum ? 'default' : 'outline'}
                      size="sm"
                      onClick={() => setPage(pageNum)}
                      className="min-w-[32px]"
                    >
                      {pageNum}
                    </Button>
                  )
                )}
              </div>
              <Button variant="outline" size="sm" disabled={page >= totalPages} onClick={() => setPage(page + 1)}>
                <ChevronRight className="h-4 w-4" />
              </Button>
              <Button variant="outline" size="sm" disabled={page >= totalPages} onClick={() => setPage(totalPages)} title="Last page">
                <ChevronRight className="h-3.5 w-3.5" />
                <ChevronRight className="-ml-2 h-3.5 w-3.5" />
              </Button>
            </div>
          </div>
        </motion.div>
      )}

      {/* Inquiry detail modal */}
      {selectedInquiry && (
        <InquiryDetailModal
          inquiry={selectedInquiry}
          isOpen={!!selectedInquiry}
          onClose={() => setSelectedInquiry(null)}
        />
      )}
    </motion.div>
  );
}
