/**
 * API Error Handling
 *
 * Lightweight result type and logging utilities for Dataverse API calls.
 *
 * Every API function returns an ApiResult<T> so callers can distinguish:
 *  - success with data
 *  - success with empty result (no data found, but the call worked)
 *  - failure (network error, server error, etc.)
 *
 * USAGE PATTERN
 * ```
 * const result = await someApiCall();
 * if (!result.ok) {
 *   // Handle error — show result.error to the user
 *   return null;
 * }
 * // Use result.data
 * ```
 */

// ─── Result Type ──────────────────────────────────────────────────

export interface ApiError {
  operation: string;
  status: number;
  message: string;
  details?: string;
}

export type ApiResult<T> =
  | { ok: true; data: T }
  | { ok: false; error: ApiError };

// ─── Factory Helpers ──────────────────────────────────────────────

export function success<T>(data: T): ApiResult<T> {
  return { ok: true, data };
}

export function failure<T = never>(
  operation: string,
  status: number,
  message?: string,
  details?: string,
): ApiResult<T> {
  return {
    ok: false,
    error: { operation, status, message: message ?? 'Request failed', details },
  };
}

// ─── Error Logger ─────────────────────────────────────────────────

/**
 * Log a structured error message to the console.
 * Every API module should call this on failure, never raw console.warn.
 */
export function logApiError(
  operation: string,
  status: number,
  context?: string,
  responseText?: string,
): void {
  const msg = `[API] ${operation} failed (${status})${context ? ` — ${context}` : ''}`;
  const details = responseText ? `\n  Response: ${responseText.slice(0, 300)}` : '';
  console.warn(msg + details);
}
