/**
 * Contact API
 *
 * Dataverse operations for Contact records.
 *
 * RESPONSIBILITIES
 *  - Endpoint construction (`/_api/contacts`)
 *  - Contact creation with GUID extraction
 *  - Response mapping via DataverseMapper
 *
 * RULES
 *  - Must extract GUID from `entityid` response header.
 *  - Must use `/contacts(GUID)` @odata.bind format for related records.
 */

import * as dv from '@lib/dataverse/dataverseClient';
import { buildContactPayload, type ContactPayload } from '@lib/dataverse/mappers';
import { logApiError } from './api-error';

interface ContactInput {
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  city: string;
  country: string;
}

/**
 * Create a Contact record in Dataverse.
 * Returns the GUID of the newly created contact, or null on failure.
 */
export async function createContact(data: ContactInput): Promise<string | null> {
  const payload: ContactPayload = buildContactPayload(data);
  const response = await dv.post<undefined>('/_api/contacts', payload);

  if (!response.ok) {
    logApiError('createContact', response.status);
    return null;
  }

  const guid = response.entityId;
  if (!guid) {
    console.warn('[contactApi] createContact: no entityid in response headers');
  }
  return guid;
}
