import type { Vehicle, VehicleFilters, VehicleSortOption, VehicleHierarchy } from '@types';
import * as vehicleApi from '@apis/vehicleApi';
import * as hierarchyApi from '@apis/hierarchyApi';

export class VehicleRepository {
  async getAll(filters?: VehicleFilters, sort?: VehicleSortOption, page = 1, pageSize = 20) {
    return vehicleApi.getVehicles(filters, sort, page, pageSize);
  }

  async getById(id: string): Promise<Vehicle | null> {
    return vehicleApi.getVehicleById(id);
  }

  async getHierarchy(): Promise<VehicleHierarchy> {
    return hierarchyApi.getVehicleHierarchy();
  }

  async getSpecs(year: number, make: string, model: string): Promise<Vehicle[]> {
    return hierarchyApi.getVehicleSpecs(year, make, model);
  }

  async search(query: string, limit = 20): Promise<Vehicle[]> {
    return vehicleApi.searchVehicles(query, limit);
  }

  async getYears(): Promise<number[]> {
    return hierarchyApi.getYears();
  }

  async getMakes(year: number): Promise<string[]> {
    return hierarchyApi.getMakes(year);
  }

  async getModels(year: number, make: string): Promise<string[]> {
    return hierarchyApi.getModels(year, make);
  }

  async getSpecsList(year: number, make: string, model: string): Promise<string[]> {
    return hierarchyApi.getSpecsList(year, make, model);
  }

  async getAllVehicles(pageSize = 5000, maxPages = 10) {
    return vehicleApi.getAllVehicles(pageSize, maxPages);
  }
}

export const vehicleRepository = new VehicleRepository();
