export function entityUrl(id: string): string {
  return `/_api/vpi_vehicledatas(${id})`;
}

export function collectionUrl(query = ''): string {
  return `/_api/vpi_vehicledatas${query}`;
}

/** Escape a single-quote for OData string filters. */
export function escape(value: string): string {
  return value.replace(/'/g, "''");
}

/** Generic array chunking */
export function chunk<T>(arr: T[], size: number): T[][] {
  const chunks: T[][] = [];
  for (let i = 0; i < arr.length; i += size) {
    chunks.push(arr.slice(i, i + size));
  }
  return chunks;
}
