import { motion } from 'framer-motion';
import { useDashboardAnalytics, useAllVehicles } from '@hooks';
import { useDashboardStore } from '@stores';
import { Card, CardContent, LazyChart } from '@components/ui';
import { formatCurrency, formatNumber, cn } from '@utils';
import { useMemo } from 'react';
import {
  Car, BarChart3, DollarSign, ArrowUpRight, ArrowDownRight,
  Activity, Clock, Sparkles,
} from 'lucide-react';
import {
  TopMakesChart,
  PriceDistributionChart,
  ValueTrendChart,
  PowertrainDonutChart,
  PerformanceScatterChart,
  BodyTypeBarChart,
  AgeDistributionChart,
  VolatilityBoxChart,
  TopModelsChart,
} from './dashboard/charts';
import { PremiumLeaderboard } from './dashboard/PremiumLeaderboard';
import { VehicleIntelligenceModal } from './dashboard/VehicleIntelligenceModal';

// ─── KPI Config ──────────────────────────────────────
interface KPICardStyle {
  gradient: string;
  iconBg: string;
  iconColor: string;
  accent: string;
}

const kpiStyles: Record<string, KPICardStyle> = {
  'TOTAL VEHICLES': { gradient: 'from-blue-500/20 to-blue-600/5', iconBg: 'bg-blue-500/10', iconColor: 'text-blue-600 dark:text-blue-400', accent: 'bg-blue-500' },
  'TOTAL MAKES': { gradient: 'from-violet-500/20 to-violet-600/5', iconBg: 'bg-violet-500/10', iconColor: 'text-violet-600 dark:text-violet-400', accent: 'bg-violet-500' },
  'TOTAL MODELS': { gradient: 'from-emerald-500/20 to-emerald-600/5', iconBg: 'bg-emerald-500/10', iconColor: 'text-emerald-600 dark:text-emerald-400', accent: 'bg-emerald-500' },
  'HIGHEST VALUE': { gradient: 'from-amber-500/20 to-amber-600/5', iconBg: 'bg-amber-500/10', iconColor: 'text-amber-600 dark:text-amber-400', accent: 'bg-amber-500' },
  'AVG MARKET PRICE': { gradient: 'from-rose-500/20 to-rose-600/5', iconBg: 'bg-rose-500/10', iconColor: 'text-rose-600 dark:text-rose-400', accent: 'bg-rose-500' },
  'LOWEST VALUE': { gradient: 'from-teal-500/20 to-teal-600/5', iconBg: 'bg-teal-500/10', iconColor: 'text-teal-600 dark:text-teal-400', accent: 'bg-teal-500' },
};

const kpiConfig = [
  { label: 'TOTAL VEHICLES', value: (o: any) => formatNumber(o.totalVehicles), icon: Car, subtitle: 'In database' },
  { label: 'TOTAL MAKES', value: (o: any) => formatNumber(o.totalMakes), icon: BarChart3, subtitle: 'Manufacturers' },
  { label: 'TOTAL MODELS', value: (o: any) => formatNumber(o.totalModels), icon: Activity, subtitle: 'Unique models' },
  { label: 'HIGHEST VALUE', value: (o: any) => formatCurrency(o.highestVehicleValue), icon: ArrowUpRight, subtitle: 'Top market price' },
  { label: 'AVG MARKET PRICE', value: (o: any) => formatCurrency(o.averageMarketPrice), icon: DollarSign, subtitle: 'Across all vehicles' },
  { label: 'LOWEST VALUE', value: (o: any) => formatCurrency(o.lowestVehicleValue), icon: ArrowDownRight, subtitle: 'Bottom market price' },
];

// ─── Animations ──────────────────────────────────────
const containerVariants = {
  hidden: { opacity: 0 },
  visible: { opacity: 1, transition: { staggerChildren: 0.04 } },
};
const itemVariants = {
  hidden: { opacity: 0, y: 15 },
  visible: { opacity: 1, y: 0 },
};

function KPICardSkeleton() {
  return (
    <div className="rounded-2xl border bg-card p-5">
      <div className="animate-pulse space-y-3">
        <div className="h-3 w-24 rounded bg-muted" />
        <div className="h-7 w-20 rounded bg-muted" />
      </div>
    </div>
  );
}

// ─── Section Wrapper ─────────────────────────────────
function ChartSection({ title, subtitle, badge, children, className = '' }: {
  title: string;
  subtitle?: string;
  badge?: string;
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <motion.div variants={itemVariants} className={className}>
      <Card className="overflow-hidden border h-full">
        <div className="h-1 bg-gradient-to-r from-primary/60 to-accent/60" />
        <CardContent className="p-5 flex flex-col h-full">
          <div className="mb-4 flex items-center justify-between shrink-0">
            <div>
              <h3 className="text-sm font-semibold text-foreground">{title}</h3>
              {subtitle && <p className="text-[10px] text-muted-foreground mt-0.5">{subtitle}</p>}
            </div>
            {badge && (
              <span className="rounded-full bg-primary/10 px-2.5 py-0.5 text-[10px] font-medium text-primary">{badge}</span>
            )}
          </div>
          <div className="flex-1 min-h-0">
            {children}
          </div>
        </CardContent>
      </Card>
    </motion.div>
  );
}

// ═════════════════════════════════════════════════════
// DASHBOARD PAGE
// ═════════════════════════════════════════════════════
export function AdminDashboardPage() {
  const {
    overview: apiOverview, topMakes: apiTopMakes,
    isLoading: apiLoading,
  } = useDashboardAnalytics();

  const { data: allVehicleData, isLoading: vehiclesLoading } = useAllVehicles();
  const openModal = useDashboardStore((s) => s.openModal);
  const setFilter = useDashboardStore((s) => s.setFilter);

  // ── Compute real dashboard data from the full vehicle dataset ─────
  const liveData = useMemo(() => {
    if (!allVehicleData?.vehicles.length) return null;
    const { vehicles, rows } = allVehicleData;

    // Pricing from raw Dataverse rows
    const avgPrices = rows.map((r) => r.vpi_avgprice).filter((p): p is number => p != null && p > 0);
    const minPrices = rows.map((r) => r.vpi_minprice).filter((p): p is number => p != null);
    const maxPrices = rows.map((r) => r.vpi_maxprice).filter((p): p is number => p != null);

    const avgPrice = avgPrices.length ? avgPrices.reduce((a, b) => a + b, 0) / avgPrices.length : 0;
    const highestPrice = maxPrices.length ? Math.max(...maxPrices) : 0;
    const lowestPrice = minPrices.length ? Math.min(...minPrices) : 0;

    // Overview
    const makesSet = new Set(vehicles.map((v) => v.make).filter(Boolean));
    const modelsSet = new Set(vehicles.map((v) => v.model).filter(Boolean));
    const overview = {
      totalVehicles: vehicles.length,
      totalMakes: makesSet.size,
      totalModels: modelsSet.size,
      averageMarketPrice: avgPrice,
      highestVehicleValue: highestPrice,
      lowestVehicleValue: lowestPrice,
      priceRangeSpread: highestPrice - lowestPrice,
      lastUpdated: new Date(),
    };

    // ── Top makes by count ──
    const makeCounts = new Map<string, number>();
    vehicles.forEach((v) => { if (v.make) makeCounts.set(v.make, (makeCounts.get(v.make) ?? 0) + 1); });
    const sortedMakes = [...makeCounts.entries()].sort((a, b) => b[1] - a[1]);
    const totalMakeCount = vehicles.length || 1;
    const topMakes = sortedMakes.slice(0, 10).map(([make, count]) => ({
      make, count, averagePrice: 0,
      percentage: Math.round((count / totalMakeCount) * 10000) / 100,
    }));

    // ── Top models by count ──
    const modelCounts = new Map<string, { make: string; model: string; count: number }>();
    vehicles.forEach((v) => {
      if (v.model && v.make) {
        const key = `${v.make}:::${v.model}`;
        const existing = modelCounts.get(key);
        if (existing) existing.count++;
        else modelCounts.set(key, { make: v.make, model: v.model, count: 1 });
      }
    });
    const topModels = [...modelCounts.entries()]
      .sort((a, b) => b[1].count - a[1].count)
      .slice(0, 10)
      .map(([, data]) => ({ ...data, averagePrice: 0 }));

    // ── Age distribution (vehicles by year) ──
    const yearCounts = new Map<number, number>();
    vehicles.forEach((v) => { if (v.year) yearCounts.set(v.year, (yearCounts.get(v.year) ?? 0) + 1); });
    const ageTotal = vehicles.length || 1;
    const ageDistribution = [...yearCounts.entries()]
      .sort((a, b) => b[0] - a[0])
      .map(([year, count]) => ({ year, count, percentage: Math.round((count / ageTotal) * 10000) / 100 }));

    // ── Body type distribution ──
    const bodyTypeCounts = new Map<string, { count: number; priceSum: number }>();
    vehicles.forEach((v) => {
      if (v.bodyType) {
        const existing = bodyTypeCounts.get(v.bodyType);
        if (existing) existing.count++;
        else bodyTypeCounts.set(v.bodyType, { count: 1, priceSum: 0 });
      }
    });
    const bodyTotal = vehicles.length || 1;
    const bodyTypeDistribution = [...bodyTypeCounts.entries()]
      .sort((a, b) => b[1].count - a[1].count)
      .slice(0, 10)
      .map(([bodyType, data]) => ({
        bodyType, count: data.count, percentage: Math.round((data.count / bodyTotal) * 10000) / 100, averagePrice: 0,
      }));

    // ── Value trend (avg/median/min/max price by year) ──
    const priceByYearAcc = new Map<number, { sum: number; count: number; min: number; max: number }>();
    rows.forEach((r) => {
      const yr = r.vpi_year;
      const price = r.vpi_avgprice;
      if (yr && price != null && price > 0) {
        const existing = priceByYearAcc.get(yr);
        if (existing) {
          existing.sum += price; existing.count++;
          if (price < existing.min) existing.min = price;
          if (price > existing.max) existing.max = price;
        } else {
          priceByYearAcc.set(yr, { sum: price, count: 1, min: price, max: price });
        }
      }
    });
    const valueTrend = [...priceByYearAcc.entries()]
      .sort((a, b) => a[0] - b[0])
      .map(([year, data]) => ({
        year,
        averagePrice: Math.round(data.sum / data.count),
        medianPrice: 0, minimumPrice: data.min, maximumPrice: data.max, count: data.count,
      }));

    // ── Powertrain composition ──
    const powertrainCounts = new Map<string, number>();
    vehicles.forEach((v) => { if (v.powertrain) powertrainCounts.set(v.powertrain, (powertrainCounts.get(v.powertrain) ?? 0) + 1); });
    const powertrainTotal = vehicles.length || 1;
    const powertrainComposition = [...powertrainCounts.entries()]
      .map(([powertrain, count]) => ({ powertrain, count, averagePrice: 0, percentage: Math.round((count / powertrainTotal) * 100) }));

    // ── Scatter data (horsepower vs price) ──
    const scatterData = vehicles
      .map((v, i) => ({
        vehicleId: v.id, horsepower: v.horsepower || 0, averagePrice: avgPrices[i] ?? 0,
        make: v.make || '', model: v.model || '', spec: v.spec || '', year: v.year || 0,
      }))
      .filter((s) => s.horsepower > 0 && s.averagePrice > 0)
      .slice(0, 500);

    // ── Box plot (price stats by category) ──
    const boxRaw = new Map<string, number[]>();
    rows.forEach((r) => {
      const cat = r.vpi_category ?? 0;
      const price = r.vpi_avgprice;
      if (price != null && price > 0) {
        const key = cat === 1 ? 'GCC' : cat === 2 ? 'NON-GCC' : 'OTHER/STANDARD';
        if (!boxRaw.has(key)) boxRaw.set(key, []);
        boxRaw.get(key)!.push(price);
      }
    });
    const boxPlot = [...boxRaw.entries()].map(([category, prices]) => {
      const sorted = [...prices].sort((a, b) => a - b);
      const len = sorted.length;
      const min = sorted[0]!, q1 = sorted[Math.floor(len * 0.25)]!, median = sorted[Math.floor(len / 2)]!;
      const q3 = sorted[Math.floor(len * 0.75)]!, max = sorted[len - 1]!;
      return {
        category, min, q1, median, q3, max,
        count: len, outliers: [] as { vehicleId: string; price: number }[],
      };
    });

    // ── Price distribution buckets ──
    const bucketCount = 15;
    const maxPriceVal = Math.max(...avgPrices, 1);
    const bucketSize = maxPriceVal / bucketCount;
    const bucketRaw = Array.from({ length: bucketCount }, () => ({ count: 0, prices: [] as number[] }));
    avgPrices.forEach((p) => {
      const idx = Math.min(Math.floor(p / bucketSize), bucketCount - 1);
      bucketRaw[idx]!.count++;
      bucketRaw[idx]!.prices.push(p);
    });
    const priceDistribution = bucketRaw.map((b, i) => {
      const minVal = i * bucketSize;
      const maxVal = (i + 1) * bucketSize;
      const pct = avgPrices.length ? Math.round((b.count / avgPrices.length) * 10000) / 100 : 0;
      return { range: `${formatCurrency(Math.round(minVal))} - ${formatCurrency(Math.round(maxVal))}`, min: Math.round(minVal), max: Math.round(maxVal), count: b.count, percentage: pct };
    });

    // ── Premium leaderboard (top 100 by avg price) ──
    const matchedVehicles = vehicles
      .map((v, i) => ({
        vehicleId: v.id, make: v.make || '', model: v.model || '',
        year: v.year || 0, spec: v.spec || '',
        minPrice: minPrices[i] ?? 0, averagePrice: avgPrices[i] ?? 0, maxPrice: maxPrices[i] ?? 0,
      }))
      .filter((vp) => vp.averagePrice > 0)
      .sort((a, b) => b.averagePrice - a.averagePrice)
      .slice(0, 100)
      .map((vp, i) => ({ ...vp, rank: i + 1 }));

    return {
      overview, topMakes, topModels, priceDistribution, valueTrend,
      powertrainComposition, scatterData, bodyTypeDistribution, ageDistribution,
      boxPlot, premiumLeaderboard: matchedVehicles,
      totalFiltered: vehicles.length, totalUnfiltered: vehicles.length,
    };
  }, [allVehicleData]);

  // Use live computed data when available, fall back to API data
  const overview = liveData?.overview ?? apiOverview;
  const topMakes = liveData?.topMakes ?? apiTopMakes;
  const priceDistribution = liveData?.priceDistribution ?? [];
  const valueTrend = liveData?.valueTrend ?? [];
  const powertrainComposition = liveData?.powertrainComposition ?? [];
  const scatterData = liveData?.scatterData ?? [];
  const bodyTypeDistribution = liveData?.bodyTypeDistribution ?? [];
  const ageDistribution = liveData?.ageDistribution ?? [];
  const boxPlot = liveData?.boxPlot ?? [];
  const topModels = liveData?.topModels ?? [];
  const premiumLeaderboard = liveData?.premiumLeaderboard ?? [];
  const totalFiltered = liveData?.totalFiltered ?? 0;
  const totalUnfiltered = liveData?.totalUnfiltered ?? 0;
  const error = !liveData && !vehiclesLoading && !apiLoading ? 'No data available' : undefined;

  const isLoading = apiLoading || vehiclesLoading;

  if (isLoading) {
    return (
      <motion.div className="space-y-6" initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 0.3 }}>
        <div className="animate-pulse space-y-2">
          <div className="h-8 w-48 rounded-lg bg-muted" />
          <div className="h-4 w-72 rounded bg-muted/50" />
        </div>
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6">
          {Array.from({ length: 6 }).map((_, i) => <KPICardSkeleton key={i} />)}
        </div>
        <div className="grid gap-6 lg:grid-cols-2">
          {Array.from({ length: 4 }).map((_, i) => (
            <div key={i} className="animate-pulse rounded-2xl border bg-card p-5">
              <div className="mb-4 h-5 w-32 rounded bg-muted" />
              <div className="h-72 rounded-lg bg-muted/50" />
            </div>
          ))}
        </div>
      </motion.div>
    );
  }

  if (error || !overview) {
    return (
      <div className="flex min-h-[400px] flex-col items-center justify-center">
        <div className="mb-4 flex h-16 w-16 items-center justify-center rounded-2xl bg-destructive/10">
          <ArrowDownRight className="h-8 w-8 text-destructive" />
        </div>
        <p className="text-lg font-medium text-foreground">Failed to load analytics</p>
        <p className="mt-1 text-sm text-muted-foreground">Try refreshing the page or check your data source.</p>
      </div>
    );
  }

  return (
    <motion.div className="space-y-6" variants={containerVariants} initial="hidden" animate="visible">
      {/* ── Header ──────────────────────────────────── */}
      <motion.div variants={itemVariants}>
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold tracking-tight text-foreground">Dashboard</h1>
            <p className="text-sm text-muted-foreground">
              <span className="font-medium text-foreground">{formatNumber(overview.totalVehicles)}</span> vehicles across{' '}
              <span className="font-medium text-foreground">{formatNumber(overview.totalMakes)}</span> makes ·{' '}
              {totalFiltered !== totalUnfiltered && (
                <span className="text-primary">Filtered: {formatNumber(totalFiltered)} vehicles · </span>
              )}
              <span className="text-muted-foreground/60">
                Updated {new Date(overview.lastUpdated).toLocaleDateString()}
              </span>
            </p>
          </div>
        </div>
      </motion.div>

      {/* ── KPI Cards ──────────────────────────────── */}
      <motion.div variants={itemVariants}>
        <div className="grid gap-3 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6">
          {kpiConfig.map((kpi) => {
            const val = kpi.value(overview);
            const style: KPICardStyle = kpiStyles[kpi.label] as KPICardStyle;
            return (
              <motion.div key={kpi.label} variants={itemVariants} className="group">
                <Card className="relative h-full overflow-hidden border transition-all duration-300 hover:shadow-lg hover:-translate-y-1">
                  {/* Top accent bar */}
                  <div className={cn('h-1 bg-gradient-to-r', style.gradient)} />
                  <CardContent className="relative flex h-full flex-col p-4 pt-3.5">
                    {/* Decorative background */}
                    <div className={cn('absolute right-0 top-0 h-24 w-24 -translate-y-6 translate-x-6 rounded-full opacity-[0.03] transition-transform duration-500 group-hover:scale-150', style.accent)} />
                    <div className="flex items-center justify-between">
                      <span className="text-[10px] font-semibold uppercase tracking-widest text-muted-foreground/70">
                        {kpi.label}
                      </span>
                      <div className={cn('flex h-8 w-8 items-center justify-center rounded-xl transition-all duration-300 group-hover:scale-110 group-hover:shadow-sm', style.iconBg)}>
                        <kpi.icon className={cn('h-4 w-4', style.iconColor)} />
                      </div>
                    </div>
                    <div className="mt-3 flex items-baseline gap-2">
                      <p className="text-xl font-bold tracking-tight text-foreground">{val}</p>
                    </div>
                    <p className="mt-0.5 text-[10px] text-muted-foreground/60">{kpi.subtitle}</p>
                  </CardContent>
                </Card>
              </motion.div>
            );
          })}
        </div>
      </motion.div>

      {/* ── Section 1: Top Makes + Section 2: Price Distribution ── */}
      <div className="grid gap-6 lg:grid-cols-2">
        <ChartSection title="Top Vehicle Makes" subtitle="Highest inventory count by manufacturer" badge="Top 10">
          <LazyChart immediate height={280}>
            <TopMakesChart
              data={topMakes}
              onBarClick={(make) => setFilter('make', make)}
            />
          </LazyChart>
        </ChartSection>
        <ChartSection title="Price Distribution" subtitle="Vehicle count by market price range" badge="Histogram">
          <LazyChart immediate height={280}>
            <PriceDistributionChart data={priceDistribution} />
          </LazyChart>
        </ChartSection>
      </div>

      {/* ── Section 3: Value Trend + Section 4: Powertrain Donut ── */}
      <div className="grid gap-6 lg:grid-cols-2">
        <ChartSection title="Vehicle Value Trend" subtitle="Average price by model year" badge="Trend">
          <LazyChart immediate height={280}>
            <ValueTrendChart data={valueTrend} />
          </LazyChart>
        </ChartSection>
        <ChartSection title="Powertrain Composition" subtitle="Market share by fuel/powertrain type" badge="Donut">
          <LazyChart immediate height={280}>
            <PowertrainDonutChart data={powertrainComposition} />
          </LazyChart>
        </ChartSection>
      </div>

      {/* ── Section 5: Performance vs Value (full width) ── */}
      <div className="grid gap-6 lg:grid-cols-1">
        <ChartSection title="Performance vs Value" subtitle="How horsepower relates to market price" badge="Scatter">
          <LazyChart height={280}>
            <PerformanceScatterChart
              data={scatterData}
              onDotClick={(vehicleId) => openModal(vehicleId)}
            />
          </LazyChart>
        </ChartSection>
      </div>

      {/* ── Section 6: Category + Section 7: Age Distribution ── */}
      <div className="grid gap-6 lg:grid-cols-2">
        <ChartSection title="Vehicle Category Distribution" subtitle="Inventory composition by body type" badge="Top 10">
          <LazyChart height={280}>
            <BodyTypeBarChart data={bodyTypeDistribution} />
          </LazyChart>
        </ChartSection>
        <ChartSection title="Vehicle Age Distribution" subtitle="How old is the current inventory" badge="Area">
          <LazyChart height={280}>
            <AgeDistributionChart
              data={ageDistribution}
              onDotClick={(year) => setFilter('year', year)}
            />
          </LazyChart>
        </ChartSection>
      </div>

      {/* ── Section 8: Price Volatility + Section 9: Top Models ── */}
      <div className="grid gap-6 lg:grid-cols-2">
        <ChartSection title="Price Volatility Analysis" subtitle="Min, median, and max prices by category" badge="Range">
          <LazyChart height={280}>
            <VolatilityBoxChart data={boxPlot} />
          </LazyChart>
        </ChartSection>
        <ChartSection title="Top Vehicle Models" subtitle="Most frequent models by inventory count" badge="Top 10">
          <LazyChart height={280}>
            <TopModelsChart
              data={topModels}
              onBarClick={(model) => setFilter('model', model)}
            />
          </LazyChart>
        </ChartSection>
      </div>

      {/* ── Section 10: Premium Vehicle Leaderboard ── */}
      <motion.div variants={itemVariants}>
        <LazyChart height={400} rootMargin="300px">
          <Card className="overflow-hidden border">
            <div className="h-1 bg-gradient-to-r from-amber-500/60 to-amber-400/60" />
            <CardContent className="p-5">
              <div className="mb-4 flex items-center justify-between">
                <div>
                  <h3 className="text-sm font-semibold text-foreground">Premium Vehicle Leaderboard</h3>
                  <p className="text-[10px] text-muted-foreground mt-0.5">
                    Top {premiumLeaderboard.length} vehicles by market value
                  </p>
                </div>
                <span className="rounded-full bg-amber-500/10 px-2.5 py-0.5 text-[10px] font-medium text-amber-600 dark:text-amber-400">Top 100</span>
              </div>
              <PremiumLeaderboard
                data={premiumLeaderboard}
                onVehicleSelect={(vehicleId) => openModal(vehicleId)}
              />
            </CardContent>
          </Card>
        </LazyChart>
      </motion.div>

      {/* ── Footer ─────────────────────────────────── */}
      <motion.div variants={itemVariants}>
        <div className="flex items-center justify-center gap-2 text-xs text-muted-foreground/60">
          <Clock className="h-3 w-3" />
          <span>Last updated: {new Date(overview.lastUpdated).toLocaleDateString('en-US', {
            year: 'numeric', month: 'long', day: 'numeric',
            hour: '2-digit', minute: '2-digit',
          })}</span>
          <span className="mx-2">·</span>
          <Sparkles className="h-3 w-3" />
          <span>Live analytics · {formatNumber(totalFiltered)} vehicles displayed</span>
        </div>
      </motion.div>

      {/* ── Vehicle Intelligence Modal ──────────────── */}
      <VehicleIntelligenceModal />
    </motion.div>
  );
}
