import { useQuery } from '@tanstack/react-query';
import { vehicleRepository } from '@repositories';
import { useVehicleStore } from '@stores';
import type { VehicleFilters, VehicleSortOption } from '@types';
import { useEffect, useMemo } from 'react';

const VEHICLES_KEY = 'vehicles';
const VEHICLE_KEY = 'vehicle';
const HIERARCHY_KEY = 'vehicle-hierarchy';
const ALL_VEHICLES_KEY = 'all-vehicles';

export function useVehicles(filters?: VehicleFilters, sort?: VehicleSortOption, page = 1, pageSize = 20) {
  const setVehicles = useVehicleStore((s) => s.setVehicles);
  const setTotal = useVehicleStore((s) => s.setTotal);
  const setLoading = useVehicleStore((s) => s.setLoading);
  const setError = useVehicleStore((s) => s.setError);

  const query = useQuery({
    queryKey: [VEHICLES_KEY, { filters, sort, page, pageSize }],
    queryFn: () => vehicleRepository.getAll(filters, sort, page, pageSize),
  });

  useEffect(() => {
    if (query.data) {
      setVehicles(query.data.vehicles);
      setTotal(query.data.total);
    }
    setLoading(query.isLoading);
    if (query.error) setError(query.error.message);
  }, [query.data, query.isLoading, query.error, setVehicles, setTotal, setLoading, setError]);

  return query;
}

export function useVehicle(id: string | undefined) {
  return useQuery({
    queryKey: [VEHICLE_KEY, id],
    queryFn: () => (id ? vehicleRepository.getById(id) : null),
    enabled: !!id,
  });
}

export function useVehicleHierarchy() {
  return useQuery({
    queryKey: [HIERARCHY_KEY],
    queryFn: () => vehicleRepository.getHierarchy(),
    staleTime: Infinity,
  });
}

export function useVehicleMakes(year: number | null) {
  return useQuery({
    queryKey: ['vehicle-makes', year],
    queryFn: () => (year ? vehicleRepository.getMakes(year) : Promise.resolve([])),
    enabled: !!year,
  });
}

export function useVehicleModels(year: number | null, make: string) {
  return useQuery({
    queryKey: ['vehicle-models', year, make],
    queryFn: () => (year && make ? vehicleRepository.getModels(year, make) : Promise.resolve([])),
    enabled: !!year && !!make,
  });
}

export function useVehicleSpecs(year: number | null, make: string, model: string) {
  return useQuery({
    queryKey: ['vehicle-specs', year, make, model],
    queryFn: () => (year && make && model ? vehicleRepository.getSpecsList(year, make, model) : Promise.resolve([])),
    enabled: !!year && !!make && !!model,
  });
}

export function useVehicleSearch(query: string) {
  return useQuery({
    queryKey: ['vehicle-search', query],
    queryFn: () => vehicleRepository.search(query),
    enabled: query.length >= 2,
    staleTime: 30_000,
  });
}

/**
 * Fetch ALL vehicles from Dataverse (paginated via @odata.nextLink).
 * Data is cached indefinitely since the full dataset is static.
 */
export function useAllVehicles() {
  return useQuery({
    queryKey: [ALL_VEHICLES_KEY],
    queryFn: () => vehicleRepository.getAllVehicles(),
    staleTime: Infinity,
    retry: 2,
  });
}

/**
 * Derive cascading filter options from the full vehicle list.
 *
 * Cascade order: Make → Model → Spec → Year → BodyType
 * Each step narrows by ALL prior selections.
 */
export function useVehicleCascade(
  make: string,
  model: string,
  spec: string,
  year: number | null,
) {
  const { data, isLoading } = useAllVehicles();
  const vehicles = data?.vehicles ?? [];

  const allMakes = useMemo(
    () => [...new Set(vehicles.map((v) => v.make).filter(Boolean))].sort(),
    [vehicles],
  );

  // Filtered by make
  const byMake = useMemo(
    () => (make ? vehicles.filter((v) => v.make === make) : vehicles),
    [vehicles, make],
  );

  // Filtered by make + model
  const byModel = useMemo(
    () => (model ? byMake.filter((v) => v.model === model) : byMake),
    [byMake, model],
  );

  // Filtered by make + model + spec
  const bySpec = useMemo(
    () => (spec ? byModel.filter((v) => v.spec === spec) : byModel),
    [byModel, spec],
  );

  // Filtered by make + model + spec + year
  const byYear = useMemo(
    () => (year ? bySpec.filter((v) => v.year === year) : bySpec),
    [bySpec, year],
  );

  const models = useMemo(
    () => [...new Set(byMake.map((v) => v.model).filter(Boolean))].sort(),
    [byMake],
  );

  const specs = useMemo(
    () => [...new Set(byModel.map((v) => v.spec).filter(Boolean))].sort(),
    [byModel],
  );

  const years = useMemo(
    () => [...new Set(bySpec.map((v) => v.year).filter(Boolean))].sort((a, b) => b - a),
    [bySpec],
  );

  const bodyTypes = useMemo(
    () => [...new Set(byYear.map((v) => v.bodyType).filter(Boolean))].sort(),
    [byYear],
  );

  return {
    allMakes,
    models,
    specs,
    years,
    bodyTypes,
    isLoading,
    totalVehicles: vehicles.length,
  };
}

