/**
 * Inquiry API
 *
 * Dataverse operations for Vehicle Inquiry records.
 *
 * RESPONSIBILITIES
 *  - Endpoint construction (`/_api/vpi_vehicleinquiries`)
 *  - Inquiry CRUD with @odata.bind lookups
 *  - Contact + Inquiry two-step save
 *  - Inquiry status updates
 *
 * RULES
 *  - Must use `/contacts(GUID)` and `/vpi_vehicledatas(GUID)` bind syntax.
 *  - Inquiry status is stored as an integer (option set).
 *  - Never crash on missing lookups.
 */

import type { Inquiry, InquiryStatus } from '@types';

import * as dv from '@lib/dataverse/dataverseClient';
import {
  buildInquiryPayload,
  getFormattedValue,
  type DataverseInquiryRow,
} from '@lib/dataverse/mappers';

import { createContact } from '@apis/contactApi';
import { logApiError } from './api-error';

// ─── Constants ─────────────────────────────────────────────────────

const INQUIRY_SELECT = [
  'vpi_vehicleinquiryid',
  '_vpi_contact_value',
  '_vpi_vehicle_value',
  'vpi_status',
  'createdon',
].join(',');

// ─── Inquiry CRUD ──────────────────────────────────────────────────

/**
 * Create a Vehicle Inquiry record, linking a Contact and a Vehicle.
 *
 * @param contactGuid  GUID of the Contact
 * @param vehicleGuid  GUID of the Vehicle
 * @param status       Inquiry status (default: pending)
 * @returns            GUID of the created inquiry, or null on failure
 */
export async function createVehicleInquiry(
  contactGuid: string,
  vehicleGuid: string,
  status: InquiryStatus = 'pending',
): Promise<string | null> {
  const payload = buildInquiryPayload(contactGuid, vehicleGuid, status);
  const response = await dv.post<undefined>('/_api/vpi_vehicleinquiries', payload);

  if (!response.ok) {
    logApiError('createVehicleInquiry', response.status);
    return null;
  }

  return response.entityId;
}

/**
 * Save a complete inquiry: creates the Contact first, then links it to
 * a Vehicle via the Vehicle Inquiry entity.
 *
 * If vehicleGuid is not provided, attempts to resolve it from the
 * inquiry's selectedVehicle criteria.
 */
export async function saveInquiry(
  inquiry: Inquiry,
  vehicleGuid?: string,
): Promise<{ inquiryId: string | null; contactId: string | null }> {
  // 1. Create the Contact
  const contactId = await createContact({
    firstName: inquiry.firstName,
    lastName: inquiry.lastName,
    email: inquiry.email,
    phone: inquiry.phone,
    city: inquiry.city,
    country: inquiry.country,
  });

  if (!contactId) {
    return { inquiryId: null, contactId: null };
  }

  // 2. Resolve vehicle GUID if not provided
  let resolvedVehicleGuid: string | undefined | null = vehicleGuid;
  if (!resolvedVehicleGuid && inquiry.selectedVehicle) {
    resolvedVehicleGuid = await resolveVehicleGuid(inquiry.selectedVehicle);
  }

  if (!resolvedVehicleGuid) {
    console.warn('[inquiryApi] saveInquiry: could not resolve vehicle GUID');
    return { inquiryId: null, contactId };
  }

  // 3. Create the Vehicle Inquiry
  const inquiryId = await createVehicleInquiry(
    contactId,
    resolvedVehicleGuid,
    inquiry.status,
  );

  return { inquiryId, contactId };
}

/**
 * Get all vehicle inquiries.
 */
export async function getInquiries(): Promise<Inquiry[]> {
  const url = `/_api/vpi_vehicleinquiries?$select=${INQUIRY_SELECT}&$orderby=createdon desc&$top=100`;
  const response = await dv.get<{
    value: DataverseInquiryRow[];
    '@odata.nextLink'?: string;
  }>(url);

  if (!response.ok) return [];

  return (response.data.value ?? []).map((row) => {
    const statusLabel = getFormattedValue(
      row as unknown as Record<string, unknown>,
      'vpi_status',
    );
    const statusStr = statusLabel?.toLowerCase() ?? 'pending';
    return {
      id: row.vpi_vehicleinquiryid ?? crypto.randomUUID(),
      firstName: '',
      lastName: '',
      email: '',
      phone: '',
      country: '',
      city: '',
      consent: false,
      selectedVehicle: { year: 0, make: '', model: '', spec: '', bodyType: '' },
      createdAt: new Date(),
      status: (
        statusStr === 'reviewed' || statusStr === 'contacted' || statusStr === 'closed'
          ? statusStr
          : 'pending'
      ) as InquiryStatus,
    };
  });
}

/**
 * Get a single inquiry by ID.
 *
 * Queries Dataverse directly by GUID — does NOT load all records.
 */
export async function getInquiryById(id: string): Promise<Inquiry | null> {
  const url = `/_api/vpi_vehicleinquiries(${id})?$select=${INQUIRY_SELECT}`;
  const response = await dv.get<DataverseInquiryRow>(url);
  if (!response.ok) return null;

  const row = response.data;
  const statusLabel = getFormattedValue(
    row as unknown as Record<string, unknown>,
    'vpi_status',
  );
  const statusStr = statusLabel?.toLowerCase() ?? 'pending';

  return {
    id: row.vpi_vehicleinquiryid ?? id,
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    country: '',
    city: '',
    consent: false,
    selectedVehicle: { year: 0, make: '', model: '', spec: '', bodyType: '' },
    createdAt: new Date(),
    status: (
      statusStr === 'reviewed' || statusStr === 'contacted' || statusStr === 'closed'
        ? statusStr
        : 'pending'
    ) as InquiryStatus,
  };
}

/**
 * Update inquiry status.
 */
export async function updateInquiryStatus(
  id: string,
  status: InquiryStatus,
): Promise<boolean> {
  const statusInt = statusToInt(status);
  if (statusInt == null) {
    console.warn(
      `[inquiryApi] updateInquiryStatus: unknown status "${status}"`,
    );
    return false;
  }

  const response = await dv.patch(
    `/_api/vpi_vehicleinquiries(${id})`,
    { vpi_status: statusInt },
  );

  return response.ok;
}

// ─── Private Helpers ───────────────────────────────────────────────

/**
 * Resolve a vehicle GUID from selection criteria.
 */
async function resolveVehicleGuid(selection: {
  year: number;
  make: string;
  model: string;
  spec: string;
}): Promise<string | null> {
  const filter = `vpi_year eq ${selection.year} and vpi_make eq '${escape(selection.make)}' and vpi_model eq '${escape(selection.model)}' and vpi_spec eq '${escape(selection.spec)}'`;
  const url = `/_api/vpi_vehicledatas?$select=vpi_vehicledataid&$filter=${encodeURIComponent(filter)}&$top=1`;

  const response = await dv.get<{ value: { vpi_vehicledataid?: string }[] }>(url);
  if (!response.ok || !response.data.value?.[0]) return null;

  return response.data.value[0].vpi_vehicledataid ?? null;
}

// Import needed for updateInquiryStatus
function statusToInt(value: string): number | null {
  const MAP: Record<string, number> = {
    pending: 1,
    reviewed: 2,
    contacted: 3,
    closed: 4,
  };
  return MAP[value] ?? null;
}

function escape(value: string): string {
  return value.replace(/'/g, "''");
}
