/**
 * Dataverse Mapper
 *
 * Option set mappings and field converters for the Dataverse integration.
 *
 * RULES:
 *  - Use only the schema/values defined in APPENDIX_A_DATAVERSE_IMPLEMENTATION_REFERENCE.md.
 *  - Never invent option set values.
 *  - If a value is missing: log warning, continue execution, never crash.
 *
 * All Dataverse reads use `Prefer: odata.include-annotations=*` so formatted
 * display labels arrive alongside raw option-set integers.  We use the
 * formatted labels when reading and the integer values when writing.
 */

import type {
  Vehicle,
  VehiclePricing,
  VehicleHierarchy,
  VehicleFilters,
  DriveType,
  VehicleType,
  VehicleCategory,
  PowertrainType,
  Inquiry,
  InquiryStatus,
  ValuationResult,
  PriceRange,
  MarketTrend,
} from '@types';

// ─── Logging helper ──────────────────────────────────────────────

function warn(missing: string, value: unknown, context: string): void {
  if (typeof console !== 'undefined' && console.warn) {
    console.warn(`[DataverseMapper] ${missing}: "${value}" in ${context}`);
  }
}

