// ─── Generic formatted-value extractor ───────────────────────────

/**
 * Extract a formatted (display) value from a Dataverse API response row
 * for an option-set or lookup field.
 *
 * Example: row["vpi_drivetype@OData.Community.Display.V1.FormattedValue"]
 */
export function getFormattedValue(row: Record<string, unknown>, field: string): string | undefined {
  const key = `${field}@OData.Community.Display.V1.FormattedValue`;
  const val = row[key];
  return val != null ? String(val) : undefined;
}

/**
 * Extract a lookup GUID from a Dataverse API response row.
 *
 * Example: row["_vpi_contact_value"] returns the GUID string.
 */
export function getLookupValue(row: Record<string, unknown>, field: string): string | undefined {
  const val = row[`_${field}_value`];
  return val != null ? String(val) : undefined;
}

// ─── Incoming Vehicle (Dataverse JSON → App Vehicle) ─────────────

export interface DataverseVehicleRow {
  vpi_vehicledataid?: string;
  vpi_year?: number;
  vpi_make?: string;
  vpi_model?: string;
  vpi_spec?: string;
  vpi_enginesize?: number;
  vpi_horsepower?: number;
  vpi_cylinders?: number;
  vpi_doors?: number;
  vpi_seats?: number;
  vpi_transmissiontronic?: number;
  vpi_bodytype?: number;
  vpi_drivetype?: number;
  vpi_vehicletype?: number;
  vpi_category?: number;
  vpi_powertraintype?: number;
  vpi_description?: string;
  vpi_minprice?: number;
  vpi_avgprice?: number;
  vpi_maxprice?: number;
  vpi_pricespreadpct?: number;
  vpi_makecode?: string;
  vpi_modelcode?: string;
  vpi_yearcode?: string;
  [key: string]: unknown;
}

export function rowToVehicle(row: DataverseVehicleRow): Vehicle {
  const id = row.vpi_vehicledataid ?? '';
  const year = row.vpi_year ?? 0;
  const make = String(row.vpi_make ?? '').trim();
  const model = String(row.vpi_model ?? '').trim();
  const spec = String(row.vpi_spec ?? '').trim();

  // Use formatted value for option-set fields where available
  const driveTypeLabel = getFormattedValue(row as unknown as Record<string, unknown>, 'vpi_drivetype');
  const vehicleTypeLabel = getFormattedValue(row as unknown as Record<string, unknown>, 'vpi_vehicletype');
  const categoryLabel = getFormattedValue(row as unknown as Record<string, unknown>, 'vpi_category');
  const powertrainLabel = getFormattedValue(row as unknown as Record<string, unknown>, 'vpi_powertraintype');
  const bodyTypeLabel = getFormattedValue(row as unknown as Record<string, unknown>, 'vpi_bodytype');
  const transmissionLabel = getFormattedValue(row as unknown as Record<string, unknown>, 'vpi_transmissiontronic');

  const vehicle: Vehicle = {
    id,
    year,
    make,
    model,
    spec,
    trim: spec,
    engineSize: row.vpi_enginesize ?? 0,
    horsepower: row.vpi_horsepower ?? 0,
    cylinders: row.vpi_cylinders ?? 0,
    doors: row.vpi_doors ?? 0,
    seats: row.vpi_seats ?? 0,
    transmission: (transmissionLabel ?? String(row.vpi_transmissiontronic ?? '')) as Vehicle['transmission'],
    bodyType: (bodyTypeLabel ?? String(row.vpi_bodytype ?? '')) as Vehicle['bodyType'],
    driveType: (driveTypeLabel ?? 'Unknown') as DriveType,
    vehicleType: (vehicleTypeLabel ?? 'Car') as VehicleType,
    category: (categoryLabel ?? 'OTHER/STANDARD') as VehicleCategory,
    powertrain: (powertrainLabel ?? 'Petrol/Diesel') as PowertrainType,
    description: String(row.vpi_description ?? ''),
  };

  if (!id) warn('Missing vpi_vehicledataid', row, 'rowToVehicle');
  if (!year) warn('Missing vpi_year', row, 'rowToVehicle');
  if (!make) warn('Missing vpi_make', row, 'rowToVehicle');

  return vehicle;
}

// ─── Pricing from vehicle row ────────────────────────────────────

export function rowToPricing(vehicleId: string, row: DataverseVehicleRow): VehiclePricing {
  const avg = row.vpi_avgprice ?? 0;
  const min = row.vpi_minprice ?? 0;
  const max = row.vpi_maxprice ?? 0;
  const median = avg;
  const stdDev = max > min ? Math.round((max - min) * 0.2) : 0;

  const priceRange: PriceRange = {
    min,
    max,
    average: avg,
    median,
    p10: Math.round(min + (avg - min) * 0.3),
    p25: Math.round(min + (avg - min) * 0.5),
    p75: Math.round(max - (max - avg) * 0.5),
    p90: Math.round(max - (max - avg) * 0.3),
  };

  const marketTrend: MarketTrend = {
    direction: 'stable',
    percentage: 0,
    periodMonths: 3,
    volatility: 'low',
  };

  const sampleSize = avg > 0 ? 1 : 0;
  const confidenceScore = avg > 0 ? Math.min(60, 40 + sampleSize * 5) : 0;

  return {
    vehicleId,
    averagePrice: avg,
    minimumPrice: min,
    maximumPrice: max,
    medianPrice: median,
    standardDeviation: stdDev,
    sampleSize,
    priceRange,
    confidenceScore,
    marketTrend,
    lastUpdated: new Date(),
  };
}

// ─── OData Filter Builder ────────────────────────────────────────

/**
 * Build an OData `$filter` string from app-level VehicleFilters.
 * Only produces filters that can be expressed server-side (no pricing
 * cross-references, no text-search via computed fields).
 */
export function buildVehicleFilter(filters?: VehicleFilters): string {
  if (!filters) return '';

  const clauses: string[] = [];

  if (filters.year) clauses.push(`vpi_year eq ${filters.year}`);
  if (filters.minYear) clauses.push(`vpi_year ge ${filters.minYear}`);
  if (filters.maxYear) clauses.push(`vpi_year le ${filters.maxYear}`);

  if (filters.make) {
    clauses.push(`vpi_make eq '${escapeODataString(filters.make)}'`);
  }
  if (filters.model) {
    clauses.push(`vpi_model eq '${escapeODataString(filters.model)}'`);
  }
  if (filters.spec) {
    clauses.push(`vpi_spec eq '${escapeODataString(filters.spec)}'`);
  }

  // Option-set fields — use integer value
  if (filters.bodyType) {
    const bt = bodyTypeToInt(filters.bodyType);
    if (bt != null) clauses.push(`vpi_bodytype eq ${bt}`);
    else warn('Unknown bodyType', filters.bodyType, 'buildVehicleFilter');
  }

  if (filters.driveType) {
    const dt = driveTypeToInt(filters.driveType);
    if (dt != null) clauses.push(`vpi_drivetype eq ${dt}`);
    else warn('Unknown driveType', filters.driveType, 'buildVehicleFilter');
  }

  if (filters.vehicleType) {
    const vt = vehicleTypeToInt(filters.vehicleType);
    if (vt != null) clauses.push(`vpi_vehicletype eq ${vt}`);
    else warn('Unknown vehicleType', filters.vehicleType, 'buildVehicleFilter');
  }

  if (filters.category) {
    const cat = categoryToInt(filters.category);
    if (cat != null) clauses.push(`vpi_category eq ${cat}`);
    else warn('Unknown category', filters.category, 'buildVehicleFilter');
  }

  if (filters.powertrain) {
    const pt = powertrainToInt(filters.powertrain);
    if (pt != null) clauses.push(`vpi_powertraintype eq ${pt}`);
    else warn('Unknown powertrain', filters.powertrain, 'buildVehicleFilter');
  }

  if (filters.transmission) {
    const tr = transmissionToInt(filters.transmission);
    if (tr != null) clauses.push(`vpi_transmissiontronic eq ${tr}`);
    else warn('Unknown transmission', filters.transmission, 'buildVehicleFilter');
  }

  return clauses.join(' and ');
}

/**
 * Build an OData `$orderby` string.
 */
export function buildVehicleOrderBy(
  field: string,
  direction: 'asc' | 'desc' = 'desc',
): string {
  const f = VEHICLE_SORT_TO_ODATA[field] ?? 'vpi_year';
  return `${f} ${direction}`;
}

const VEHICLE_SORT_TO_ODATA: Record<string, string> = {
  year: 'vpi_year',
  make: 'vpi_make',
  model: 'vpi_model',
  price: 'vpi_avgprice',
  horsepower: 'vpi_horsepower',
  engineSize: 'vpi_enginesize',
};

// ─── Contact Payload Builder ─────────────────────────────────────

export interface ContactPayload {
  firstname: string;
  lastname: string;
  emailaddress1: string;
  telephone1: string;
  vpi_city: number | null;
  vpi_country: string;
}

export function buildContactPayload(inquiry: {
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  city: string;
  country: string;
}): ContactPayload {
  const cityInt = cityToInt(inquiry.city);
  if (cityInt == null) {
    warn('Unknown city for contact creation', inquiry.city, 'buildContactPayload');
  }

  return {
    firstname: inquiry.firstName,
    lastname: inquiry.lastName,
    emailaddress1: inquiry.email,
    telephone1: inquiry.phone,
    vpi_city: cityInt,
    vpi_country: inquiry.country,
  };
}

// ─── Vehicle Inquiry Payload Builder ─────────────────────────────

export interface VehicleInquiryPayload {
  'vpi_Contact@odata.bind': string;
  'vpi_Vehicle@odata.bind': string;
  vpi_status: number;
}

export function buildInquiryPayload(
  contactGuid: string,
  vehicleGuid: string,
  status: InquiryStatus = 'pending',
): VehicleInquiryPayload {
  const statusInt = statusToInt(status);

  return {
    'vpi_Contact@odata.bind': `/contacts(${contactGuid})`,
    'vpi_Vehicle@odata.bind': `/vpi_vehicledatas(${vehicleGuid})`,
    vpi_status: statusInt ?? 1, // default to Pending
  };
}

// ─── OData String Escaping ───────────────────────────────────────

function escapeODataString(value: string): string {
  return value.replace(/'/g, "''");
}

// ─── Dataverse Inquiry Row → App Inquiry ─────────────────────────

export interface DataverseInquiryRow {
  vpi_vehicleinquiryid?: string;
  _vpi_contact_value?: string;
  _vpi_vehicle_value?: string;
  vpi_status?: number;
  [key: string]: unknown;
}

export function rowToInquiry(
  row: DataverseInquiryRow,
  _contact?: { firstname?: string; lastname?: string; emailaddress1?: string; telephone1?: string; vpi_city?: number; vpi_country?: string },
  _vehicle?: { year?: number; make?: string; model?: string; spec?: string; bodyType?: string },
  _valuation?: ValuationResult,
): Inquiry {
  const status = intToStatus(row.vpi_status ?? 0);

  return {
    id: row.vpi_vehicleinquiryid ?? crypto.randomUUID(),
    firstName: _contact?.firstname ?? '',
    lastName: _contact?.lastname ?? '',
    email: _contact?.emailaddress1 ?? '',
    phone: _contact?.telephone1 ?? '',
    country: _contact?.vpi_country ?? '',
    city: _contact?.vpi_city != null ? (intToCity(_contact.vpi_city) ?? String(_contact.vpi_city)) : '',
    consent: false,
    selectedVehicle: {
      year: _vehicle?.year ?? 0,
      make: _vehicle?.make ?? '',
      model: _vehicle?.model ?? '',
      spec: _vehicle?.spec ?? '',
      bodyType: _vehicle?.bodyType ?? '',
    },
    valuationResult: _valuation,
    createdAt: new Date(),
    status: status ?? 'pending',
  };
}

// ─── Hierarchy Helpers ───────────────────────────────────────────

/**
 * Build a VehicleHierarchy from sets of known years / makes / models / specs.
 */
export function buildVehicleHierarchy(data: {
  years: number[];
  makes: Record<number, string[]>;
  models: Record<string, string[]>;
  specs: Record<string, string[]>;
}): VehicleHierarchy {
  return {
    years: data.years,
    makes: data.makes,
    models: data.models,
    specs: data.specs,
    bodyTypes: {},
    transmissions: {},
    driveTypes: {},
    categories: {},
    powertrains: {},
    vehicleTypes: {},
  };
}
