/**
 * Analytics API
 *
 * Dataverse operations for admin analytics and dashboard charts.
 *
 * RESPONSIBILITIES
 *  - Admin dashboard analytics (KPI overview + chart data)
 *  - Full analytics export (all vehicles with pricing)
 *  - Server-side aggregation using OData $apply
 *
 * RULES
 *  - Use $apply (groupby/aggregate) for server-side computation.
 *  - Never load all 33k+ records in a single request.
 *  - Chart data that cannot be computed server-side is returned as [].
 */

import type {
  AnalyticsData,
  AnalyticsOverview,
  DashboardAnalytics,
  DashboardFilters,
  Vehicle,
  VehicleFilters,
  VehiclePricing,
} from '@types';

import * as dv from '@lib/dataverse/dataverseClient';
import {
  rowToVehicle,
  rowToPricing,
  buildVehicleFilter,
  type DataverseVehicleRow,
} from '@lib/dataverse/mappers';
import { collectionUrl } from './api-utils';
import { resolveNextLink } from '@lib/dataverse/dataverseClient';
import { logApiError } from './api-error';

