/**
 * Get full analytics for the admin dashboard.
 *
 * NOTE: Overview stats use server-side aggregation ($apply). Chart-level
 * data (countByMake, priceDistribution, etc.) relies on $apply grouping
 * which may not be available in all Dataverse environments â€” when absent,
 * these arrays are returned empty. The UI renders gracefully in both cases.
 */
export async function getAnalytics(): Promise<AnalyticsData> {
  const overviewUrl = collectionUrl(
    '?$apply=groupby((),aggregate(vpi_avgprice with average as avgPrice,vpi_minprice with min as minPrice,vpi_maxprice with max as maxPrice))',
  );
  const overviewRes = await dv.get<{
    value?: { avgPrice?: number; minPrice?: number; maxPrice?: number }[];
  }>(overviewUrl);

  const countUrl = collectionUrl('?$count=true&$top=1');
  const countRes = await dv.get<{ '@odata.count'?: number }>(countUrl);

  // Distinct makes count via $apply groupby
  const makesUrl = collectionUrl('?$apply=groupby((vpi_make),aggregate($count as count))&$count=true&$top=5000');
  const makesRes = await dv.get<{ '@odata.count'?: number }>(makesUrl);

  // Distinct models count via $apply groupby
  const modelsUrl = collectionUrl('?$apply=groupby((vpi_model),aggregate($count as count))&$count=true&$top=5000');
  const modelsRes = await dv.get<{ '@odata.count'?: number }>(modelsUrl);

  const totals = overviewRes.data.value?.[0];
  const avgPrice = totals?.avgPrice ?? 0;
  const minPrice = totals?.minPrice ?? 0;
  const maxPrice = totals?.maxPrice ?? 0;

  const overview: AnalyticsOverview = {
    totalVehicles: countRes.data['@odata.count'] ?? 0,
    totalMakes: makesRes.data['@odata.count'] ?? 0,
    totalModels: modelsRes.data['@odata.count'] ?? 0,
    averageMarketPrice: avgPrice,
    highestVehicleValue: maxPrice,
    lowestVehicleValue: minPrice,
    priceRangeSpread: maxPrice - minPrice,
    lastUpdated: new Date(),
  };

  return {
    overview,
    countByMake: [],
    countByModel: [],
    priceDistribution: [],
    priceByYear: [],
    priceByCategory: [],
    transmissionAnalysis: [],
    driveTypeAnalysis: [],
    powertrainAnalysis: [],
    bodyTypeAnalysis: [],
  };
}

/**
 * Get dashboard analytics â€” uses server-side grouping for chart data.
 *
 * Chart data that cannot be computed via server-side $apply is returned
 * as an empty array. The dashboard UI handles empty chart states gracefully.
 */
export async function getDashboardAnalytics(
  _filters?: DashboardFilters,
): Promise<DashboardAnalytics> {
  // Compute overview counts by make using $apply
  const makeCountUrl = collectionUrl(
    '?$apply=groupby((vpi_make),aggregate($count as count))&$orderby=count desc&$top=10',
  );
  const makeRes = await dv.get<{
    value: { vpi_make?: string; count?: number }[];
  }>(makeCountUrl);

  const overviewByMake = (makeRes.data.value ?? []).map((r) => ({
    make: r.vpi_make ?? 'Unknown',
    count: r.count ?? 0,
  }));

  // Model counts
  const modelCountUrl = collectionUrl(
    '?$apply=groupby((vpi_make,vpi_model),aggregate($count as count))&$orderby=count desc&$top=20',
  );
  const modelRes = await dv.get<{
    value: { vpi_make?: string; vpi_model?: string; count?: number }[];
  }>(modelCountUrl);

  const overviewByModel = (modelRes.data.value ?? []).map((r) => ({
    make: r.vpi_make ?? '',
    model: r.vpi_model ?? '',
    count: r.count ?? 0,
  }));

  // Average price by make â€” merge into overviewByMake
  const avgPriceUrl = collectionUrl(
    '?$apply=groupby((vpi_make),aggregate(vpi_avgprice with average as avgPrice))',
  );
  const priceRes = await dv.get<{
    value: { vpi_make?: string; avgPrice?: number }[];
  }>(avgPriceUrl);

  const avgPriceByMakeMap = new Map<string, number>();
  for (const r of priceRes.data.value ?? []) {
    if (r.vpi_make) avgPriceByMakeMap.set(r.vpi_make, r.avgPrice ?? 0);
  }

  const totalMakeCount = overviewByMake.reduce((sum, m) => sum + m.count, 0) || 1;

  const topMakes = overviewByMake.map((m) => ({
    make: m.make,
    count: m.count,
    averagePrice: avgPriceByMakeMap.get(m.make) ?? 0,
    percentage: Math.round((m.count / totalMakeCount) * 10000) / 100,
  }));

  const topModels = overviewByModel.map((m) => ({
    make: m.make,
    model: m.model,
    count: m.count,
    averagePrice: avgPriceByMakeMap.get(m.make) ?? 0,
  }));

  // Compute real overview stats server-side
  const aggUrl = collectionUrl(
    '?$apply=groupby((),aggregate(vpi_avgprice with average as avgPrice,vpi_minprice with min as minPrice,vpi_maxprice with max as maxPrice))',
  );
  const aggRes = await dv.get<{
    value?: { avgPrice?: number; minPrice?: number; maxPrice?: number }[];
  }>(aggUrl);
  const agg = aggRes.data.value?.[0];
  const avgPrice = agg?.avgPrice ?? 0;
  const minPrice = agg?.minPrice ?? 0;
  const maxPrice = agg?.maxPrice ?? 0;

  const countUrl = collectionUrl('?$count=true&$top=1');
  const countRes = await dv.get<{ '@odata.count'?: number }>(countUrl);
  const totalRecords = countRes.data['@odata.count'] ?? 0;

  // Count distinct makes and models
  const makesUrl = collectionUrl('?$apply=groupby((vpi_make),aggregate($count as count))&$count=true&$top=5000');
  const modelsUrl = collectionUrl('?$apply=groupby((vpi_model),aggregate($count as count))&$count=true&$top=5000');
  const [makesCountRes, modelsCountRes] = await Promise.all([
    dv.get<{ '@odata.count'?: number }>(makesUrl),
    dv.get<{ '@odata.count'?: number }>(modelsUrl),
  ]);

  const overview: AnalyticsOverview = {
    totalVehicles: totalRecords,
    totalMakes: makesCountRes.data['@odata.count'] ?? 0,
    totalModels: modelsCountRes.data['@odata.count'] ?? 0,
    averageMarketPrice: avgPrice,
    highestVehicleValue: maxPrice,
    lowestVehicleValue: minPrice,
    priceRangeSpread: maxPrice - minPrice,
    lastUpdated: new Date(),
  };

  const totalUnfiltered = totalRecords;

  return {
    overview,
    topMakes,
    priceDistribution: [],
    valueTrend: [],
    powertrainComposition: [],
    scatterData: [],
    bodyTypeDistribution: [],
    ageDistribution: [],
    boxPlot: [],
    topModels,
    premiumLeaderboard: [],
    totalFiltered: totalRecords,
    totalUnfiltered,
  };
}

/**
 * Get all vehicles with their pricing (analytics export).
 * Uses pagination internally â€” never loads all 33k at once.
 */
export async function getAllVehiclesWithPricing(
  filters?: VehicleFilters,
): Promise<{ vehicle: Vehicle; pricing: VehiclePricing }[]> {
  // Determine how many records match with $count
  const filterClause = buildVehicleFilter(filters);
  let countUrl = collectionUrl('?$count=true&$top=1');
  if (filterClause) countUrl += `&$filter=${encodeURIComponent(filterClause)}`;

  const countRes = await dv.get<{ '@odata.count'?: number }>(countUrl);
  const total = countRes.data['@odata.count'] ?? 0;

  if (total === 0) return [];

  // Use paginated scan to fetch all
  const selectWithPricing = [
    'vpi_vehicledataid',
    'vpi_year',
    'vpi_make',
    'vpi_model',
    'vpi_spec',
    'vpi_enginesize',
    'vpi_horsepower',
    'vpi_cylinders',
    'vpi_doors',
    'vpi_seats',
    'vpi_transmissiontronic',
    'vpi_bodytype',
    'vpi_drivetype',
    'vpi_vehicletype',
    'vpi_category',
    'vpi_powertraintype',
    'vpi_description',
    'vpi_minprice',
    'vpi_avgprice',
    'vpi_maxprice',
  ].join(',');

  let scanUrl = collectionUrl(
    `?$select=${selectWithPricing}&$top=5000`,
  );
  if (filterClause) scanUrl += `&$filter=${encodeURIComponent(filterClause)}`;

  const result: { vehicle: Vehicle; pricing: VehiclePricing }[] = [];
  let nextLink: string | null = scanUrl;
  let pages = 0;
  const MAX_PAGES = 8;

  while (nextLink && pages < MAX_PAGES) {
    const res = await dv.get<{
      value: DataverseVehicleRow[];
      '@odata.nextLink'?: string;
    }>(nextLink);

    if (!res.ok) {
      logApiError('getAllVehiclesWithPricing scan', res.status, `page=${pages + 1}`);
      break;
    }

    const rows = res.data.value ?? [];
    for (const row of rows) {
      const vehicle = rowToVehicle(row);
      const pricing = rowToPricing(vehicle.id, row);
      result.push({ vehicle, pricing });
    }

    nextLink = resolveNextLink(res.data['@odata.nextLink']);
    pages++;
  }

  return result;
}

