/**
 * Pricing API
 *
 * Dataverse operations for vehicle pricing, valuation, and comparables.
 *
 * RESPONSIBILITIES
 *  - Pricing lookup by vehicle ID or criteria
 *  - Valuation computation (pricing + comparables + insights)
 *  - Comparable vehicle scoring
 *  - Aggregate price range queries
 *
 * RULES
 *  - Pricing fields are stored directly on the vehicle entity.
 *  - Never load all 33k+ records for comparables — use server-side filtering.
 */

import type {
  Vehicle,
  VehiclePricing,
  VehicleFilters,
  ValuationResult,
  ComparableVehicle,
  MarketInsight,
} from '@types';

import * as dv from '@lib/dataverse/dataverseClient';
import {
  rowToVehicle,
  rowToPricing,
  buildVehicleFilter,
  type DataverseVehicleRow,
} from '@lib/dataverse/mappers';
import {
  PRICING_SELECT,
  VEHICLE_SELECT,
  entityUrl,
  collectionUrl,
  escape,
} from './api-utils';
import { logApiError } from './api-error';

// ─── Pricing ───────────────────────────────────────────────────────

/**
 * Get pricing for a single vehicle.
 * Pricing fields are stored directly on the vehicle entity.
 */
export async function getPricing(
  vehicleId: string,
): Promise<VehiclePricing | null> {
  const url = `${entityUrl(vehicleId)}?$select=${PRICING_SELECT}`;
  const response = await dv.get<DataverseVehicleRow>(url);
  if (!response.ok) {
    logApiError('getPricing', response.status, `vehicleId=${vehicleId}`);
    return null;
  }

  return rowToPricing(vehicleId, response.data);
}

/**
 * Get pricing by year/make/model/spec criteria.
 */
export async function getPricingByCriteria(
  year: number,
  make: string,
  model: string,
  spec: string,
): Promise<VehiclePricing | null> {
  const filter = `vpi_year eq ${year} and vpi_make eq '${escape(make)}' and vpi_model eq '${escape(model)}' and vpi_spec eq '${escape(spec)}'`;
  const url = collectionUrl(
    `?$select=${PRICING_SELECT}&$filter=${encodeURIComponent(filter)}&$top=1`,
  );

  const response = await dv.get<{ value: DataverseVehicleRow[] }>(url);
  if (!response.ok || !response.data.value?.[0]) return null;

  const row = response.data.value[0];
  return rowToPricing(row.vpi_vehicledataid ?? '', row);
}

/**
 * Get comparable vehicles — same make, ±3 years, exclude self.
 */
export async function getComparableVehicles(
  vehicleId: string,
  limit = 5,
): Promise<ComparableVehicle[]> {
  // First, fetch the base vehicle to get its properties
  const baseVehicle = await getVehicleForComparables(vehicleId);
  if (!baseVehicle) return [];

  const minYear = baseVehicle.year - 3;
  const maxYear = baseVehicle.year + 3;
  const filter = `vpi_make eq '${escape(baseVehicle.make)}' and vpi_year ge ${minYear} and vpi_year le ${maxYear}`;
  const url = collectionUrl(
    `?$select=${VEHICLE_SELECT}&$filter=${encodeURIComponent(filter)}&$top=20`,
  );

  const response = await dv.get<{ value: DataverseVehicleRow[] }>(url);
  if (!response.ok) return [];

  const candidates = response.data.value ?? [];
  const basePricing = await getPricing(vehicleId);
  const basePrice = basePricing?.averagePrice ?? 0;
  const comparables: ComparableVehicle[] = [];

  for (const row of candidates) {
    const id = row.vpi_vehicledataid ?? '';
    if (id === vehicleId) continue;

    const vehicle = rowToVehicle(row);
    const pricing = rowToPricing(id, row);
    if (pricing.averagePrice <= 0) continue;

    // Simple similarity scoring
    const yearDiff = Math.abs(vehicle.year - baseVehicle.year);
    let similarityScore = 0;
    if (vehicle.model.toLowerCase() === baseVehicle.model.toLowerCase()) similarityScore += 40;
    similarityScore += Math.max(0, 30 - yearDiff * 10);
    if (vehicle.bodyType === baseVehicle.bodyType) similarityScore += 15;
    if (vehicle.transmission === baseVehicle.transmission) similarityScore += 10;

    const priceDiff = pricing.averagePrice - basePrice;
    const diffPct = basePrice > 0 ? (priceDiff / basePrice) * 100 : 0;

    comparables.push({
      vehicle,
      pricing,
      similarityScore,
      priceDifference: priceDiff,
      priceDifferencePercentage: diffPct,
    });
  }

  return comparables
    .sort((a, b) => b.similarityScore - a.similarityScore)
    .slice(0, limit);
}

/**
 * Get a complete valuation for a vehicle.
 */
export async function getValuation(
  year: number,
  make: string,
  model: string,
  spec: string,
  bodyType?: string,
): Promise<ValuationResult | null> {
  let filter = `vpi_year eq ${year} and vpi_make eq '${escape(make)}' and vpi_model eq '${escape(model)}' and vpi_spec eq '${escape(spec)}'`;
  if (bodyType) {
    const btVal = requireBodyTypeInt(bodyType);
    filter += ` and vpi_bodytype eq ${btVal}`;
  }

  const url = collectionUrl(
    `?$select=${VEHICLE_SELECT}&$filter=${encodeURIComponent(filter)}&$top=1`,
  );
  const response = await dv.get<{ value: DataverseVehicleRow[] }>(url);

  if (!response.ok || !response.data.value?.length) return null;

  const row = response.data.value[0]!;
  const vehicle = rowToVehicle(row);
  const pricing = rowToPricing(vehicle.id, row);
  const comparables = await getComparableVehicles(vehicle.id, 5);
  const marketInsights = generateMarketInsights(vehicle, pricing);
  const confidenceIndicator = computeConfidence(pricing);

  return {
    vehicle,
    pricing,
    comparables,
    marketInsights,
    confidenceIndicator,
  };
}

/**
 * Get aggregate price statistics (min, max, average) using OData $apply.
 */
export async function getPriceRange(
  filters?: VehicleFilters,
): Promise<{ min: number; max: number; average: number }> {
  const filterClause = buildVehicleFilter(filters);
  let url = collectionUrl(
    '?$apply=aggregate(vpi_minprice with min as minPrice,vpi_maxprice with max as maxPrice,vpi_avgprice with average as avgPrice)',
  );
  if (filterClause) {
    url += `&$filter=${encodeURIComponent(filterClause)}`;
  }

  const response = await dv.get<{
    value?: { minPrice?: number; maxPrice?: number; avgPrice?: number }[];
  }>(url);

  if (response.ok && response.data.value?.length) {
    const agg = response.data.value[0]!;
    return {
      min: agg.minPrice ?? 0,
      max: agg.maxPrice ?? 0,
      average: agg.avgPrice ?? 0,
    };
  }

  return { min: 0, max: 0, average: 0 };
}

/**
 * Batch fetch pricing for multiple vehicle IDs — eliminates N+1 queries.
 */
export async function batchGetPricing(
  vehicleIds: string[],
): Promise<Map<string, VehiclePricing>> {
  if (vehicleIds.length === 0) return new Map();

  const results = await Promise.all(vehicleIds.map((id) => getPricing(id)));
  const map = new Map<string, VehiclePricing>();
  for (let i = 0; i < vehicleIds.length; i++) {
    const pricing = results[i];
    if (pricing) map.set(vehicleIds[i]!, pricing);
  }
  return map;
}

// ─── Private Helpers ───────────────────────────────────────────────

/** Fetch a single vehicle row without importing from vehicleApi (avoids circular deps). */
async function getVehicleForComparables(id: string): Promise<Vehicle | null> {
  const url = `${entityUrl(id)}?$select=${VEHICLE_SELECT}`;
  const response = await dv.get<DataverseVehicleRow>(url);
  if (!response.ok) {
    logApiError('getVehicleForComparables', response.status, `vehicleId=${id}`);
    return null;
  }
  return rowToVehicle(response.data);
}

function requireBodyTypeInt(bodyType: string): number {
  const MAP: Record<string, number> = {
    SUV: 1, Sedan: 2, Coupe: 3, Convertible: 4,
    Hatchback: 5, Wagon: 6, Pickup: 7, Van: 8,
    Crossover: 9, Supercar: 10,
  };
  return MAP[bodyType] ?? 1;
}

function generateMarketInsights(
  _vehicle: Vehicle,
  _pricing: VehiclePricing,
): MarketInsight[] {
  return [
    {
      type: 'regional',
      title: 'UAE Market Overview',
      description:
        'The UAE automotive market shows robust demand for pre-owned vehicles with good specification levels.',
      severity: 'neutral',
    },
  ];
}

function computeConfidence(
  pricing: VehiclePricing,
): ValuationResult['confidenceIndicator'] {
  if (pricing.sampleSize >= 50 && pricing.confidenceScore >= 85) return 'very-high';
  if (pricing.sampleSize >= 30 && pricing.confidenceScore >= 70) return 'high';
  if (pricing.sampleSize >= 15 && pricing.confidenceScore >= 50) return 'moderate';
  if (pricing.sampleSize >= 5) return 'low';
  return 'very-low';
}
