/**
 * Dataverse Client
 *
 * Centralised HTTP client for Microsoft Dataverse communication inside
 * Power Pages.  This is the **ONLY** layer that talks to Dataverse.
 *
 * RESPONSIBILITIES
 *  - GET / POST / PATCH / DELETE
 *  - Token injection (via safeAjax or shell.getTokenDeferred + fetch)
 *  - Pagination (@odata.nextLink)
 *  - Retry handling (transient failures)
 *  - Error logging (never throw â€” always return a result)
 *  - Entity ID extraction from response headers
 *
 * RULES
 *  - All Dataverse requests go through this client.
 *  - No component may bypass this layer.
 *  - Endpoints MUST use the `/_api/<entityset>` format.
 *  - Never crash on unexpected responses.
 *
 * TRANSPORT
 *  Tries `webapi.safeAjax` first (legacy Power Pages runtime). Falls back
 *  to `shell.getTokenDeferred()` + `fetch()` when safeAjax is unavailable
 *  (Enhanced data model / powerpages-host runtime).
 *
 * @see APPENDIX_A_DATAVERSE_IMPLEMENTATION_REFERENCE.md
 */

// â”€â”€â”€ Types â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

export interface DataverseResponse<T> {
  ok: boolean;
  status: number;
  data: T;
  /** GUID of the created/updated entity (extracted from response headers) */
  entityId: string | null;
}

export interface PaginatedResult<T> {
  value: T[];
  count: number;
}

/** Minimal JQuery-like types for the safeAjax wrapper. */
interface JqXHR {
  status: number;
  responseJSON?: unknown;
  responseText?: string;
  getResponseHeader(name: string): string | null;
}

interface AjaxOptions {
  type: string;
  url: string;
  contentType: string;
  data?: string;
  headers?: Record<string, string>;
}

// â”€â”€â”€ Retry Configuration â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

const MAX_RETRIES = 2;
const RETRY_DELAY_MS = 500;

// â”€â”€â”€ Internal request helper â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

function buildUrl(path: string): string {
  // If the path already starts with /, use it as-is
  if (path.startsWith('/')) return path;
  // Otherwise prefix with /_api/
  return `/_api/${path}`;
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

// ─── Auth ──────────────────────────────────────────────────────────

/**
 * Get the Power Pages anti-forgery token.
 *
 * Tries `shell.getTokenDeferred()` first (available on pages rendered
 * through the Power Pages template pipeline). Falls back to reading the
 * `__RequestVerificationToken` cookie.
 */
function getAuthToken(): Promise<string> {
  return new Promise((resolve, reject) => {
    const shell = (window as any).shell;
    if (shell?.getTokenDeferred) {
      const deferred = shell.getTokenDeferred();
      if (typeof deferred.done === 'function') {
        deferred.done(resolve);
        deferred.fail(reject);
        return;
      }
    }
    // Cookie fallback
    const match = document.cookie.match(/__RequestVerificationToken=([^;]+)/);
    if (match) {
      resolve(decodeURIComponent(match[1] ?? ''));
    } else {
      reject(new Error('No auth mechanism available (shell.getTokenDeferred and cookie both missing)'));
    }
  });
}

/** Result of a successful transport call. */
interface TransportSuccess {
  data: unknown;
  jqXHR: JqXHR;
}

/**
 * Call Dataverse via `webapi.safeAjax` (legacy Power Pages runtime).
 * Available when the SPA runs inside a page template with header/footer.
 */
function callSafeAjax(options: AjaxOptions): Promise<TransportSuccess> {
  const safeAjax = (window as any).webapi?.safeAjax;
  if (typeof safeAjax !== 'function') {
    return Promise.reject(new Error('webapi.safeAjax is not available'));
  }

  return new Promise((resolve, reject) => {
    try {
      const promise = safeAjax(options);
      if (typeof promise.done === 'function' && typeof promise.fail === 'function') {
        promise.done((data: unknown, _textStatus: string, jqXHR: JqXHR) => {
          resolve({ data, jqXHR });
        });
        promise.fail((jqXHR: JqXHR, textStatus: string, errorThrown: string) => {
          reject([jqXHR, textStatus, errorThrown]);
        });
      } else {
        reject(new Error('safeAjax did not return a thenable'));
      }
    } catch (err) {
      reject(err);
    }
  });
}

/**
 * Call Dataverse via `fetch()` with the Power Pages auth token.
 *
 * Fallback when `webapi.safeAjax` is not registered (Enhanced data model /
 * @microsoft/powerpages-host runtime).
 */
async function callFetchApi(options: AjaxOptions): Promise<TransportSuccess> {
  let token = '';
  try {
    token = await getAuthToken();
  } catch (err) {
    console.warn(
      '[DataverseClient] Could not retrieve auth token, proceeding without token:',
      err instanceof Error ? err.message : String(err),
    );
  }

  const headers: Record<string, string> = {
    'Content-Type': options.contentType,
    Accept: 'application/json',
  };

  if (options.headers) {
    Object.assign(headers, options.headers);
  }

  if (token) {
    headers['__RequestVerificationToken'] = token;
  }

  const response = await fetch(options.url, {
    method: options.type,
    headers,
    body: options.data,
  });

  const responseText = await response.text();

  // Parse JSON body for both success and error paths
  let parsed: unknown;
  try {
    parsed = JSON.parse(responseText);
  } catch {
    parsed = responseText;
  }

  const jqXHR: JqXHR = {
    status: response.status,
    responseText,
    responseJSON: parsed,
    getResponseHeader: (name: string) => response.headers.get(name),
  };

  if (!response.ok) {
    throw [jqXHR, 'error', response.statusText];
  }

  const data = response.status === 204 ? undefined : parsed;

  return { data, jqXHR };
}

/**
 * Try all available transport strategies in order:
 *  1. `webapi.safeAjax` (legacy runtime)
 *  2. `fetch` with `shell.getTokenDeferred()` (Enhanced runtime)
 *  3. `fetch` with cookie token (last resort)
 *
 * Returns a transport success or rejects with the safeAjax-style error
 * array `[jqXHR, textStatus, errorThrown]`.
 */
async function callTransport(options: AjaxOptions): Promise<TransportSuccess> {
  // Strategy 1: safeAjax
  const safeAjax = (window as any).webapi?.safeAjax;
  if (typeof safeAjax === 'function') {
    try {
      return await callSafeAjax(options);
    } catch (err) {
      // If safeAjax failed for a non-auth reason, propagate
      if (Array.isArray(err)) {
        throw err;
      }
      // Auth/unavailable error — fall through to fetch
      console.warn('[DataverseClient] safeAjax unavailable, trying fetch fallback');
    }
  }

  // Strategy 2 & 3: fetch with token
  return callFetchApi(options);
}

async function doRequest<T>(
  method: string,
  url: string,
  data?: string,
  attempt = 0,
  headers?: Record<string, string>,
): Promise<DataverseResponse<T>> {
  const options: AjaxOptions = {
    type: method,
    url: buildUrl(url),
    contentType: 'application/json',
  };

  if (headers) {
    options.headers = { ...headers };
  }

  if (data && method !== 'GET' && method !== 'DELETE') {
    options.data = data;
  }

  try {
    const { data: responseData, jqXHR } = await callTransport(options);
    const entityId = jqXHR?.getResponseHeader?.('entityid') ?? null;
    return {
      ok: true,
      status: jqXHR?.status ?? 200,
      data: (responseData ?? {}) as T,
      entityId,
    };
  } catch (err: unknown) {
    // Unwrap the rejection array if it came from safeAjax fail
    const jqXHR: JqXHR | null =
      Array.isArray(err) && err.length >= 1 ? (err[0] as JqXHR) : null;
    const status = jqXHR?.status ?? 0;

    const textStatus: string | null =
      Array.isArray(err) && err.length >= 2 ? String(err[1] ?? '') : null;
    const errorThrown: string | null =
      Array.isArray(err) && err.length >= 3 ? String(err[2] ?? '') : null;
    const isCancellation =
      status === 0 &&
      (textStatus === 'abort' || textStatus === 'canceled' || errorThrown === 'abort');

    const isTransient = status === 429 || status === 503 || status === 504;
    if (isTransient && attempt < MAX_RETRIES) {
      console.warn(
        `[DataverseClient] Retry ${attempt + 1}/${MAX_RETRIES} for ${method} ${url} (${status})`,
      );
      await sleep(RETRY_DELAY_MS * (attempt + 1));
      return doRequest<T>(method, url, data, attempt + 1);
    }
    if (isCancellation) {
      console.info(`[DataverseClient] ${method} ${url} canceled by client`);
      return {
        ok: false,
        status,
        data: ({} as T),
        entityId: null,
      };
    }

    console.error(
      `[DataverseClient] ${method} ${url} failed (${status})${jqXHR?.responseText ? ` â€” ${jqXHR.responseText.slice(0, 200)}` : ''}`,
    );
    return {
      ok: false,
      status,
      data: (jqXHR as any)?.responseJSON ?? ({} as T),
      entityId: null,
    };
  }
}

