/**
 * Execute a GET request against the Dataverse API.
 *
 * @param path Relative API path, e.g. `vpi_vehicledatas?$top=20`
 *             OR absolute `/_api/vpi_vehicledatas?$top=20`.
 *             The `/_api/` prefix is prepended automatically if absent.
 */
export async function get<T>(path: string, headers?: Record<string, string>): Promise<DataverseResponse<T>> {
  return doRequest<T>('GET', path, undefined, 0, headers);
}

/**
 * Execute a POST request (create a new record).
 *
 * Returns the response with `entityId` set to the new record's GUID
 * (extracted from the `entityid` response header).
 */
export async function post<T>(path: string, data: unknown): Promise<DataverseResponse<T>> {
  return doRequest<T>('POST', path, JSON.stringify(data));
}

/**
 * Execute a PATCH request (update an existing record).
 */
export async function patch<T>(path: string, data: unknown): Promise<DataverseResponse<T>> {
  return doRequest<T>('PATCH', path, JSON.stringify(data));
}

/**
 * Execute a DELETE request.
 */
export async function del(path: string): Promise<DataverseResponse<undefined>> {
  return doRequest<undefined>('DELETE', path);
}

/**
 * Fetch ALL pages of a paginated result, automatically following
 * `@odata.nextLink` until exhaustion.
 *
 * @param path   Initial API path
 * @param limit  Maximum pages to follow (prevents runaway loops)
 */
export async function getAllPages<T>(
  path: string,
  limit = 10,
  headers?: Record<string, string>,
): Promise<PaginatedResult<T>> {
  const all: T[] = [];
  let nextLink: string | null = path;
  let pages = 0;

  /** Page shape for @odata.nextLink pagination. */
  interface Page<TItem> {
    value?: TItem[];
    '@odata.count'?: number;
    '@odata.nextLink'?: string;
  }

  while (nextLink && pages < limit) {
    const response: DataverseResponse<Page<T>> = await get<Page<T>>(nextLink, headers);

    if (!response.ok) break;

    if (response.data.value) {
      all.push(...response.data.value);
    }

    nextLink = response.data['@odata.nextLink'] ?? null;
    pages++;
  }

  return {
    value: all,
    count: all.length,
  };
}

/**
 * Extract the resolved nextLink URL from a page response.
 *
 * Dataverse returns absolute URLs like
 *   https://org.crm6.dynamics.com/api/data/v9.2/vpi_vehicledatas?$skiptoken=X
 * This converts them to Power Pages proxy format: /_api/<entityset>?<query>
 */
export function resolveNextLink(nextLink: string | undefined | null): string | null {
  if (!nextLink) return null;
  try {
    const parsed = new URL(nextLink);
    const pathParts = parsed.pathname.split('/').filter(Boolean);
    const entitySet = pathParts[pathParts.length - 1];
    if (entitySet) {
      return `/_api/${entitySet}${parsed.search}`;
    }
    return parsed.pathname + parsed.search;
  } catch {
    // Already a relative URL or malformed - use as-is
    return nextLink.startsWith('/') ? nextLink : `/${nextLink}`;
  }
}